import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Language {
  code: string;
  name: string;
  flag?: string;
}

export interface TranslationResult {
  detectedSourceLanguage: string;
  transcribedText?: string;
  translatedText: string;
}

export interface TranslationHistoryItem extends TranslationResult {
  id: string;
  timestamp: number;
  targetLanguage: string;
  type: 'text' | 'image';
  preview?: string; // Text snippet or image thumbnail base64
}

import { GoogleGenAI, Type } from "@google/genai";
import { TranslationResult } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API_KEY is missing from environment variables.");
}

const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key-for-build' });

/**
 * Translates text or image content to the target language.
 */
export const translateContent = async (
  input: string | { image: string; mimeType: string },
  targetLanguage: string
): Promise<TranslationResult> => {
  try {
    const isImage = typeof input !== 'string';

    const parts = [];

    if (isImage) {
      parts.push({
        inlineData: {
          data: (input as { image: string }).image,
          mimeType: (input as { mimeType: string }).mimeType,
        }
      });
      parts.push({
        text: `Analyze this image. Transcribe any text found in the image exactly as it appears. Then, translate that text into ${targetLanguage}.`
      });
    } else {
      parts.push({
        text: `Translate the following text into ${targetLanguage}: "${input}"`
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: parts
      },
      config: {
        systemInstruction: "You are an expert translator. Automatically detect the source language. Return the result in strictly valid JSON format.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detectedSourceLanguage: { type: Type.STRING, description: "The name of the language detected in the input." },
            transcribedText: { type: Type.STRING, description: "The original text found in the input (OCR result if image, or the raw text if text input)." },
            translatedText: { type: Type.STRING, description: "The final translation." }
          },
          required: ["detectedSourceLanguage", "transcribedText", "translatedText"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as TranslationResult;

  } catch (error) {
    console.error("Translation Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { ChevronDown, Search, Check } from 'lucide-react';
import { Language } from '../types';
import { SUPPORTED_LANGUAGES } from '../constants';

interface LanguageSelectorProps {
  selectedLanguage: Language;
  onSelectLanguage: (lang: Language) => void;
  label?: string;
}

const LanguageSelector: React.FC<LanguageSelectorProps> = ({
  selectedLanguage,
  onSelectLanguage,
  label
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredLanguages = useMemo(() => {
    return SUPPORTED_LANGUAGES.filter(lang =>
      lang.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  return (
    <div className="relative w-full md:w-64" ref={containerRef}>
      {label && <label className="block text-xs font-medium text-secondary mb-1">{label}</label>}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between bg-surface border border-slate-700 hover:border-slate-500 text-white px-4 py-2.5 rounded-lg transition-colors shadow-sm"
      >
        <span className="flex items-center gap-2">
          <span className="text-xl">{selectedLanguage.flag}</span>
          <span className="font-medium">{selectedLanguage.name}</span>
        </span>
        <ChevronDown size={16} className={`text-secondary transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-surface border border-slate-700 rounded-lg shadow-xl max-h-80 flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-100">
          <div className="p-2 border-b border-slate-700 sticky top-0 bg-surface">
            <div className="relative">
              <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-secondary" />
              <input
                type="text"
                placeholder="Search language..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                autoFocus
                className="w-full bg-slate-800 text-white text-sm rounded-md pl-9 pr-3 py-2 outline-none focus:ring-1 focus:ring-primary placeholder-slate-500"
              />
            </div>
          </div>

          <div className="overflow-y-auto flex-1 p-1">
            {filteredLanguages.length === 0 ? (
              <div className="p-3 text-sm text-secondary text-center">No languages found</div>
            ) : (
              filteredLanguages.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => {
                    onSelectLanguage(lang);
                    setIsOpen(false);
                    setSearchTerm('');
                  }}
                  className={`w-full text-left px-3 py-2 rounded-md flex items-center justify-between hover:bg-slate-700 transition-colors group ${
                    selectedLanguage.code === lang.code ? 'bg-slate-700/50' : ''
                  }`}
                >
                  <span className="flex items-center gap-3">
                    <span className="text-lg">{lang.flag}</span>
                    <span className="text-sm text-slate-200">{lang.name}</span>
                  </span>
                  {selectedLanguage.code === lang.code && (
                    <Check size={14} className="text-primary" />
                  )}
                </button>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default LanguageSelector;

