import React, { useState, useCallback, useRef } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Maximize2,
  Sparkles,
  Menu
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [inputText, setInputText] = useState('');
  const [selectedImage, setSelectedImage] = useState<{ url: string; base64: string; mimeType: string } | null>(null);
  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);
  const [history, setHistory] = useState<TranslationHistoryItem[]>([]);
  const [showMobileHistory, setShowMobileHistory] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Extract base64 data and mime type
        const base64Data = base64String.split(',')[1];
        const mimeType = file.type;

        setSelectedImage({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: mimeType
        });
        setResult(null); // Clear previous result
      };
      reader.readAsDataURL(file);
    }
  };

  const clearImage = () => {
    setSelectedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if ((!inputText.trim() && !selectedImage)) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = selectedImage 
        ? { image: selectedImage.base64, mimeType: selectedImage.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);

      // Add to history
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: selectedImage ? 'image' : 'text',
        preview: selectedImage ? translation.transcribedText : inputText
      };

      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error("Translation failed", error);
      alert("Something went wrong with the translation service. Please check your API Key or try again.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });

    // Attempt to set target lang if found
    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedImage(null);
    } else if (item.type === 'image') {
      // For images in history, we might not have the original image blob stored (to save memory)
      // So we switch to text mode displaying the transcribed text
      setInputText(item.transcribedText || "");
      setSelectedImage(null); 
    }

    setShowMobileHistory(false);
  };

  return (
    <div className="min-h-screen flex bg-background text-slate-200 overflow-hidden font-sans">

      {/* Sidebar (Desktop) */}
      <HistorySidebar 
        history={history} 
        onClearHistory={() => setHistory([])} 
        onSelectHistoryItem={loadHistoryItem}
      />

      {/* Mobile History Drawer (Overlay) */}
      {showMobileHistory && (
        <div className="fixed inset-0 z-50 lg:hidden flex">
          <div className="w-64 h-full bg-surface shadow-2xl relative">
            <button 
              onClick={() => setShowMobileHistory(false)}
              className="absolute top-4 right-4 text-slate-400"
            >
              <X size={20} />
            </button>
            <HistorySidebar 
               history={history} 
               onClearHistory={() => setHistory([])} 
               onSelectHistoryItem={loadHistoryItem}
            />
          </div>
          <div className="flex-1 bg-black/50 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)}></div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto w-full">
        {/* Header */}
        <header className="h-16 border-b border-slate-700 flex items-center justify-between px-6 bg-surface/50 backdrop-blur sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <button className="lg:hidden text-slate-400 hover:text-white" onClick={() => setShowMobileHistory(true)}>
              <Menu size={24} />
            </button>
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-violet-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Sparkles size={18} className="text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              Polyglot AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
             {/* Add API Status or User Profile here if needed */}
             <div className="text-xs font-mono text-slate-500 hidden md:block">
                Powered by Gemini 3
             </div>
          </div>
        </header>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full flex flex-col gap-6">

          {/* Controls Bar */}
          <div className="bg-surface border border-slate-700 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-lg">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <span className="text-sm font-medium text-slate-400">Auto Detect</span>
              <ArrowRightLeft className="text-slate-600" size={16} />
              <LanguageSelector 
                selectedLanguage={targetLanguage}
                onSelectLanguage={setTargetLanguage}
              />
            </div>

            <button
              onClick={handleTranslate}
              disabled={isTranslating || (!inputText && !selectedImage)}
              className="w-full md:w-auto px-8 py-2.5 bg-primary hover:bg-blue-600 disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed text-white font-semibold rounded-lg shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"
            >
              {isTranslating ? (
                <>
                  <Loader2 size={18} className="animate-spin" /> Translating...
                </>
              ) : (
                <>
                  <Bot size={18} /> Translate
                </>
              )}
            </button>
          </div>

          {/* Translation Area */}
          <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[400px]">

            {/* INPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden focus-within:ring-2 focus-within:ring-primary/50 transition-all relative group">
                {/* Panel Header */}
                <div className="h-12 border-b border-slate-700/50 flex items-center justify-between px-4 bg-slate-900/30">
                  <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Source</span>
                  <div className="flex items-center gap-2">
                    <input 
                      type="file" 
                      accept="image/*" 
                      className="hidden" 
                      ref={fileInputRef}
                      onChange={handleImageUpload}
                    />
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                      title="Upload Image"
                    >
                      <ImageIcon size={16} />
                    </button>
                    {inputText && (
                      <button 
                         onClick={() => setInputText('')}
                         className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                         title="Clear text"
                      >
                        <X size={16} />
                      </button>
                    )}
                  </div>
                </div>

                {/* Input Content */}
                <div className="flex-1 relative p-4">
                  {selectedImage ? (
                    <div className="w-full h-full flex flex-col items-center justify-center relative bg-black/20 rounded-lg border border-dashed border-slate-700">
                      <img 
                        src={selectedImage.url} 
                        alt="Upload preview" 
                        className="max-h-64 object-contain mb-4 rounded shadow-lg" 
                      />
                      <button 
                        onClick={clearImage}
                        className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
                      >
                        <X size={14} />
                      </button>
                      <div className="text-xs text-slate-500 font-mono">Image loaded for analysis</div>
                    </div>
                  ) : (
                    <textarea
                      value={inputText}
                      onChange={(e) => setInputText(e.target.value)}
                      placeholder="Type text or upload an image to translate..."
                      className="w-full h-full bg-transparent border-none outline-none resize-none text-slate-200 placeholder-slate-600 leading-relaxed text-lg"
                      spellCheck={false}
                    />
                  )}

                  {/* Drop Overlay (Visual only, simple implementation) */}
                  {!selectedImage && !inputText && (
                     <div className="absolute inset-0 pointer-events-none flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                        <div className="flex flex-col items-center text-slate-600">
                           <Upload size={32} className="mb-2" />
                           <span className="text-sm">Type or drag image here</span>
                        </div>
                     </div>
                  )}
                </div>
              </div>
            </div>

            {/* OUTPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden relative">
                {/* Panel Header */}
                <div className="h-12 border-b border-slate-700/50 flex items-center justify-between px-4 bg-slate-900/30">
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Target</span>
                    {result && (
                       <span className="px-2 py-0.5 bg-primary/20 text-primary text-xs rounded-full border border-primary/20">
                          Detected: {result.detectedSourceLanguage}
                       </span>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => result && handleCopy(result.translatedText)}
                      className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                      disabled={!result}
                      title="Copy Translation"
                    >
                      <Copy size={16} />
                    </button>
                  </div>
                </div>

                {/* Output Content */}
                <div className="flex-1 p-4 relative bg-slate-900/20">
                   {isTranslating ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-3">
                         <div className="relative">
                            <div className="w-12 h-12 rounded-full border-4 border-slate-700 border-t-primary animate-spin"></div>
                            <Bot className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-400" size={20} />
                         </div>
                         <p className="text-sm animate-pulse">AI is working its magic...</p>
                      </div>
                   ) : result ? (
                      <div className="h-full overflow-y-auto">
                         <p className="text-lg text-white leading-relaxed whitespace-pre-wrap">
                            {result.translatedText}
                         </p>
                         {result.transcribedText && selectedImage && (
                            <div className="mt-8 pt-4 border-t border-slate-700/50">
                               <p className="text-xs text-slate-500 uppercase tracking-wider mb-2">Original Text from Image</p>
                               <p className="text-sm text-slate-400 italic">
                                  "{result.transcribedText}"
                               </p>
                            </div>
                         )}
                      </div>
                   ) : (
                      <div className="h-full flex items-center justify-center text-slate-600">
                         <p>Translation will appear here</p>
                      </div>
                   )}
                </div>
              </div>
            </div>

          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

{
  "name": "Polyglot AI Dashboard",
  "description": "A professional AI-powered translation dashboard capable of translating text, images, documents, and audio into multiple languages.",
  "requestFramePermissions": [
