export interface Language {
  code: string;
  name: string;
  flag?: string;
}

export interface TranslationResult {
  detectedSourceLanguage: string;
  transcribedText?: string;
  translatedText: string;
}

export type InputMode = 'text' | 'image' | 'document' | 'audio_file';

export interface TranslationHistoryItem extends TranslationResult {
  id: string;
  timestamp: number;
  targetLanguage: string;
  type: InputMode | 'live_session';
  preview?: string; // Text snippet or image thumbnail base64
}

import { Blob } from '@google/genai';

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import { GoogleGenAI, Type } from "@google/genai";
import { TranslationResult } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API_KEY is missing from environment variables.");
}

// Export the instance for use in LiveSession
export const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key-for-build' });

/**
 * Translates text or media content to the target language.
 */
export const translateContent = async (
  input: string | { data: string; mimeType: string },
  targetLanguage: string
): Promise<TranslationResult> => {
  try {
    const isMedia = typeof input !== 'string';

    const parts = [];

    if (isMedia) {
      const mediaInput = input as { data: string; mimeType: string };
      parts.push({
        inlineData: {
          data: mediaInput.data,
          mimeType: mediaInput.mimeType,
        }
      });

      // Customize prompt based on mime type
      let promptText = "";
      if (mediaInput.mimeType.startsWith("image/")) {
        promptText = `Analyze this image. Transcribe any text found in the image exactly as it appears. Then, translate that text into ${targetLanguage}.`;
      } else if (mediaInput.mimeType === "application/pdf" || mediaInput.mimeType === "text/plain") {
         promptText = `Read this document. Extract the text content and translate it into ${targetLanguage}.`;
      } else if (mediaInput.mimeType.startsWith("audio/")) {
         promptText = `Listen to this audio file. Transcribe the spoken content exactly. Then, translate the transcription into ${targetLanguage}.`;
      } else {
         promptText = `Analyze this content and translate it into ${targetLanguage}.`;
      }

      parts.push({ text: promptText });
    } else {
      parts.push({
        text: `Translate the following text into ${targetLanguage}: "${input}"`
      });
    }

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: parts
      },
      config: {
        systemInstruction: "You are an expert translator. Automatically detect the source language. Return the result in strictly valid JSON format.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detectedSourceLanguage: { type: Type.STRING, description: "The name of the language detected in the input." },
            transcribedText: { type: Type.STRING, description: "The original text found in the input (OCR/Transcription)." },
            translatedText: { type: Type.STRING, description: "The final translation." }
          },
          required: ["detectedSourceLanguage", "transcribedText", "translatedText"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as TranslationResult;

  } catch (error) {
    console.error("Translation Error:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import { X, Mic, MicOff, Volume2, Loader2, StopCircle } from 'lucide-react';
import { LiveServerMessage, Modality } from '@google/genai';
import { ai } from '../services/geminiService';
import { decode, decodeAudioData, createBlob } from '../utils/audioUtils';
import { Language } from '../types';

interface LiveSessionProps {
  targetLanguage: Language;
  onClose: () => void;
}

const LiveSession: React.FC<LiveSessionProps> = ({ targetLanguage, onClose }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [transcripts, setTranscripts] = useState<{ source: 'user' | 'model'; text: string }[]>([]);
  const [currentInput, setCurrentInput] = useState('');
  const [currentOutput, setCurrentOutput] = useState('');

  // Audio Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Session Ref to prevent stale closures
  const sessionPromiseRef = useRef<Promise<any> | null>(null);

  useEffect(() => {
    startSession();
    return () => stopSession();
  }, [targetLanguage]);

  const startSession = async () => {
    try {
      setIsConnected(false);
      setError(null);

      // Initialize Audio Contexts
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      inputAudioContextRef.current = new AudioContextClass({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContextClass({ sampleRate: 24000 });

      // Get Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      // Connect to Gemini Live
      sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setupAudioInput(stream);
          },
          onmessage: handleMessage,
          onclose: () => {
             console.log("Session closed");
             setIsConnected(false);
          },
          onerror: (e) => {
            console.error("Session error", e);
            setError("Connection failed. Please try again.");
            setIsConnected(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          systemInstruction: `You are a professional real-time translator. Listen to the user's speech. 
          1. Transcribe what they say. 
          2. Translate it into ${targetLanguage.name}. 
          3. Speak ONLY the translation out loud clearly. 
          Do not engage in conversation, just act as a translator voice.`
        }
      });

    } catch (err) {
      console.error(err);
      setError("Could not access microphone or connect to AI.");
    }
  };

  const setupAudioInput = (stream: MediaStream) => {
    if (!inputAudioContextRef.current || !sessionPromiseRef.current) return;

    const ctx = inputAudioContextRef.current;
    const source = ctx.createMediaStreamSource(stream);
    const processor = ctx.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);

      sessionPromiseRef.current?.then((session) => {
        session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    source.connect(processor);
    processor.connect(ctx.destination);

    scriptProcessorRef.current = processor;
    sourceNodeRef.current = source;
  };

  const handleMessage = async (message: LiveServerMessage) => {
    // 1. Handle Transcriptions (Text)
    if (message.serverContent?.inputTranscription) {
      const text = message.serverContent.inputTranscription.text;
      setCurrentInput(prev => prev + text);
    }

    if (message.serverContent?.outputTranscription) {
      const text = message.serverContent.outputTranscription.text;
      setCurrentOutput(prev => prev + text);
    }

    if (message.serverContent?.turnComplete) {
       // Commit the current turns to history
       if (currentInput || currentOutput) {
          setTranscripts(prev => [
             ...prev, 
             ...(currentInput ? [{ source: 'user' as const, text: currentInput }] : []),
             ...(currentOutput ? [{ source: 'model' as const, text: currentOutput }] : [])
          ]);
          setCurrentInput('');
          setCurrentOutput('');
       }
    }

    // 2. Handle Audio Output (Voice)
    const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (base64Audio && outputAudioContextRef.current) {
       const ctx = outputAudioContextRef.current;
       try {
         const audioBuffer = await decodeAudioData(
           decode(base64Audio),
           ctx,
           24000,
           1
         );

         const source = ctx.createBufferSource();
         source.buffer = audioBuffer;
         source.connect(ctx.destination);

         // Schedule playback
         nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
         source.start(nextStartTimeRef.current);
         nextStartTimeRef.current += audioBuffer.duration;

         source.onended = () => sourcesRef.current.delete(source);
         sourcesRef.current.add(source);

       } catch (e) {
         console.error("Audio decode error", e);
       }
    }

    // 3. Handle Interruptions
    if (message.serverContent?.interrupted) {
       sourcesRef.current.forEach(source => source.stop());
       sourcesRef.current.clear();
       nextStartTimeRef.current = 0;
       setCurrentInput(''); // Clear partials on interrupt
       setCurrentOutput('');
    }
  };

  const stopSession = () => {
    // Close Gemini Session
    sessionPromiseRef.current?.then(session => session.close());

    // Stop Microphone
    streamRef.current?.getTracks().forEach(track => track.stop());

    // Stop Processing
    scriptProcessorRef.current?.disconnect();
    sourceNodeRef.current?.disconnect();

    // Close Contexts
    inputAudioContextRef.current?.close();
    outputAudioContextRef.current?.close();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in duration-200">
      <div className="bg-surface border border-slate-700 w-full max-w-2xl h-[80vh] rounded-2xl flex flex-col shadow-2xl overflow-hidden relative">

        {/* Header */}
        <div className="p-4 border-b border-slate-700 flex items-center justify-between bg-slate-900/50">
           <div className="flex items-center gap-3">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
             <span className="font-semibold text-white">Live Translator</span>
             <span className="text-xs px-2 py-0.5 bg-primary/20 text-primary rounded-full border border-primary/20">
               Target: {targetLanguage.name}
             </span>
           </div>
           <button onClick={onClose} className="p-2 hover:bg-slate-700 rounded-full text-slate-400 hover:text-white transition-colors">
             <X size={20} />
           </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 scroll-smooth">
           {transcripts.length === 0 && !currentInput && !currentOutput && (
             <div className="flex flex-col items-center justify-center h-full text-slate-500 gap-4">
               <div className="w-20 h-20 rounded-full bg-slate-800 flex items-center justify-center relative">
                 <Mic size={32} className={isConnected ? "text-primary" : "text-slate-600"} />
                 {isConnected && (
                   <span className="absolute inset-0 rounded-full border-2 border-primary animate-ping opacity-20"></span>
                 )}
               </div>
               <p>Listening... Speak to translate.</p>
             </div>
           )}

           {transcripts.map((t, i) => (
             <div key={i} className={`flex ${t.source === 'user' ? 'justify-end' : 'justify-start'}`}>
               <div className={`max-w-[80%] rounded-2xl px-5 py-3 ${
                 t.source === 'user' 
                   ? 'bg-slate-800 text-slate-300 rounded-br-none' 
                   : 'bg-primary text-white rounded-bl-none shadow-lg shadow-blue-500/10'
               }`}>
                 <p className="text-sm leading-relaxed">{t.text}</p>
               </div>
             </div>
           ))}

           {/* Real-time partials */}
           {(currentInput || currentOutput) && (
              <div className="flex flex-col gap-2 opacity-70">
                 {currentInput && (
                   <div className="flex justify-end">
                      <div className="max-w-[80%] bg-slate-800/50 border border-dashed border-slate-600 text-slate-400 px-4 py-2 rounded-xl rounded-br-none">
                         <span className="animate-pulse">... </span>{currentInput}
                      </div>
                   </div>
                 )}
                 {currentOutput && (
                   <div className="flex justify-start">
                      <div className="max-w-[80%] bg-primary/30 border border-dashed border-primary/50 text-white px-4 py-2 rounded-xl rounded-bl-none">
                         {currentOutput}<span className="animate-pulse"> ...</span>
                      </div>
                   </div>
                 )}
              </div>
           )}

           {error && (
             <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-400 rounded-lg text-sm text-center">
               {error}
             </div>
           )}
        </div>

        {/* Footer / Controls */}
        <div className="p-6 border-t border-slate-700 bg-slate-900/30 flex justify-center">
           <button 
             onClick={onClose}
             className="flex items-center gap-2 px-6 py-3 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-all"
           >
             <StopCircle size={20} />
             <span className="font-medium">End Session</span>
           </button>
        </div>
      </div>
    </div>
  );
};

export default LiveSession;

import React, { useState, useCallback, useRef } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  Mic,
  FileIcon
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');

  // Generic Media State (Image, PDF, Audio)
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);

  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);
  const [history, setHistory] = useState<TranslationHistoryItem[]>([]);
  const [showMobileHistory, setShowMobileHistory] = useState(false);

  // Live Session State
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Extract base64 data (remove data:xxx;base64, prefix)
        const base64Data = base64String.split(',')[1];

        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = (inputMode !== 'text' && selectedMedia)
        ? { data: selectedMedia.base64, mimeType: selectedMedia.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);

      // Add to history
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: inputMode,
        preview: inputMode === 'text' ? inputText : selectedMedia?.name || 'Media File'
      };

      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error("Translation failed", error);
      alert("Something went wrong with the translation service. Please check your API Key or try again.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    if (item.type === 'live_session') return; // Cannot reload live session

    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });

    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);

    // Reset current view based on history type
    setInputMode(item.type as InputMode);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedMedia(null);
    } else {
      // We can't easily restore the file blob from history in this simple app, 
      // so we switch to text mode showing the transcription
      setInputMode('text');
      setInputText(item.transcribedText || "[Original file content not available, showing transcription]");
      setSelectedMedia(null); 
    }

    setShowMobileHistory(false);
  };

  const renderInputPreview = () => {
    if (!selectedMedia) return null;

    if (inputMode === 'image') {
      return (
        <img 
          src={selectedMedia.url} 
          alt="Upload preview" 
          className="max-h-64 object-contain mb-4 rounded shadow-lg" 
        />
      );
    } 

    if (inputMode === 'document') {
      return (
        <div className="flex flex-col items-center justify-center p-8 text-slate-300">
           <FileIcon size={64} className="mb-4 text-primary" />
           <p className="font-medium text-lg">{selectedMedia.name}</p>
           <p className="text-sm text-slate-500 uppercase mt-2">PDF / Text Document</p>
        </div>
      );
    }

    if (inputMode === 'audio_file') {
       return (
         <div className="flex flex-col items-center justify-center p-8 w-full max-w-md">
            <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 border border-slate-600">
               <Music size={32} className="text-accent" />
            </div>
            <p className="font-medium text-lg mb-4">{selectedMedia.name}</p>
            <audio controls src={selectedMedia.url} className="w-full" />
         </div>
       );
    }

    return null;
  };

  const getAcceptType = () => {
    switch (inputMode) {
      case 'image': return 'image/*';
      case 'document': return '.pdf,.txt';
      case 'audio_file': return 'audio/*';
      default: return '*/*';
    }
  };

  return (
    <div className="min-h-screen flex bg-background text-slate-200 overflow-hidden font-sans">

      {/* Live Session Overlay */}
      {isLiveSessionOpen && (
        <LiveSession 
          targetLanguage={targetLanguage} 
          onClose={() => setIsLiveSessionOpen(false)} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <HistorySidebar 
        history={history} 
        onClearHistory={() => setHistory([])} 
        onSelectHistoryItem={loadHistoryItem}
      />

      {/* Mobile History Drawer */}
      {showMobileHistory && (
        <div className="fixed inset-0 z-40 lg:hidden flex">
          <div className="w-64 h-full bg-surface shadow-2xl relative">
            <button 
              onClick={() => setShowMobileHistory(false)}
              className="absolute top-4 right-4 text-slate-400"
            >
              <X size={20} />
            </button>
            <HistorySidebar 
               history={history} 
               onClearHistory={() => setHistory([])} 
               onSelectHistoryItem={loadHistoryItem}
            />
          </div>
          <div className="flex-1 bg-black/50 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)}></div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto w-full relative z-0">
        {/* Header */}
        <header className="h-16 border-b border-slate-700 flex items-center justify-between px-6 bg-surface/50 backdrop-blur sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <button className="lg:hidden text-slate-400 hover:text-white" onClick={() => setShowMobileHistory(true)}>
              <Menu size={24} />
            </button>
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-violet-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Sparkles size={18} className="text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              Polyglot AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-xs font-mono text-slate-500 hidden md:block">
                Powered by Gemini 3
             </div>
          </div>
        </header>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full flex flex-col gap-6">

          {/* Controls Bar */}
          <div className="bg-surface border border-slate-700 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-lg">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <span className="text-sm font-medium text-slate-400">Auto Detect</span>
              <ArrowRightLeft className="text-slate-600" size={16} />
              <LanguageSelector 
                selectedLanguage={targetLanguage}
                onSelectLanguage={setTargetLanguage}
              />
            </div>

            <button
              onClick={handleTranslate}
              disabled={isTranslating || (inputMode === 'text' ? !inputText : !selectedMedia)}
              className="w-full md:w-auto px-8 py-2.5 bg-primary hover:bg-blue-600 disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed text-white font-semibold rounded-lg shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"
            >
              {isTranslating ? (
                <>
                  <Loader2 size={18} className="animate-spin" /> Translating...
                </>
              ) : (
                <>
                  <Bot size={18} /> Translate
                </>
              )}
            </button>
          </div>

          {/* Translation Area */}
          <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[400px]">

            {/* INPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden focus-within:ring-2 focus-within:ring-primary/50 transition-all relative group">
                {/* Panel Header (Toolbar) */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-2 bg-slate-900/30 overflow-x-auto">
                  <div className="flex items-center gap-1">
                    {[
                      { id: 'text', icon: FileText, label: 'Text' },
                      { id: 'image', icon: ImageIcon, label: 'Image' },
                      { id: 'document', icon: FileIcon, label: 'Doc' },
                      { id: 'audio_file', icon: Music, label: 'Audio' },
                    ].map((mode) => (
                      <button
                        key={mode.id}
                        onClick={() => {
                           setInputMode(mode.id as InputMode);
                           clearMedia();
                           setInputText('');
                        }}
                        className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all ${
                           inputMode === mode.id 
                             ? 'bg-slate-700 text-white shadow-sm' 
                             : 'text-slate-400 hover:text-white hover:bg-slate-800'
                        }`}
                      >
                         <mode.icon size={16} />
                         <span className="hidden sm:inline">{mode.label}</span>
                      </button>
                    ))}

                    <div className="w-px h-6 bg-slate-700 mx-2"></div>

                    <button
                      onClick={() => setIsLiveSessionOpen(true)}
                      className="px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all text-red-400 hover:text-red-300 hover:bg-red-500/10 border border-transparent hover:border-red-500/20"
                    >
                       <Mic size={16} />
                       <span className="hidden sm:inline font-medium">Live Voice</span>
                    </button>
                  </div>
                </div>

                {/* Input Content */}
                <div className="flex-1 relative p-4 flex flex-col">
                  {inputMode === 'text' ? (
                     <textarea
                       value={inputText}
                       onChange={(e) => setInputText(e.target.value)}
                       placeholder="Type text to translate..."
                       className="w-full h-full bg-transparent border-none outline-none resize-none text-slate-200 placeholder-slate-600 leading-relaxed text-lg"
                       spellCheck={false}
                     />
                  ) : (
                    // Media Upload Area
                    <div className="flex-1 flex flex-col items-center justify-center relative">
                       {selectedMedia ? (
                          <div className="w-full h-full flex flex-col items-center justify-center relative bg-black/20 rounded-lg border border-dashed border-slate-700 p-4">
                             {renderInputPreview()}
                             <button 
                               onClick={clearMedia}
                               className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
                             >
                               <X size={14} />
                             </button>
                             <div className="text-xs text-slate-500 font-mono mt-2">Ready to translate</div>
                          </div>
                       ) : (
                          <div 
                             className="w-full h-full border-2 border-dashed border-slate-700 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-primary/50 hover:bg-slate-800/30 transition-all group"
                             onClick={() => fileInputRef.current?.click()}
                          >
                             <input 
                               type="file" 
                               accept={getAcceptType()} 
                               className="hidden" 
                               ref={fileInputRef}
                               onChange={handleFileUpload}
                             />
                             <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                                <Upload size={28} className="text-slate-400 group-hover:text-primary" />
                             </div>
                             <p className="text-slate-400 font-medium">Click to upload {inputMode.replace('_', ' ')}</p>
                             <p className="text-xs text-slate-600 mt-2">
                                {inputMode === 'image' && 'JPG, PNG, WEBP'}
                                {inputMode === 'document' && 'PDF, TXT'}
                                {inputMode === 'audio_file' && 'MP3, WAV, M4A'}
                             </p>
                          </div>
                       )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* OUTPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden relative">
                {/* Panel Header */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-4 bg-slate-900/30">
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Target</span>
                    {result && (
                       <span className="px-2 py-0.5 bg-primary/20 text-primary text-xs rounded-full border border-primary/20">
                          Detected: {result.detectedSourceLanguage}
                       </span>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => result && handleCopy(result.translatedText)}
                      className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                      disabled={!result}
                      title="Copy Translation"
                    >
                      <Copy size={16} />
                    </button>
                  </div>
                </div>

                {/* Output Content */}
                <div className="flex-1 p-4 relative bg-slate-900/20">
                   {isTranslating ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-3">
                         <div className="relative">
                            <div className="w-12 h-12 rounded-full border-4 border-slate-700 border-t-primary animate-spin"></div>
                            <Bot className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-400" size={20} />
                         </div>
                         <p className="text-sm animate-pulse">AI is analyzing & translating...</p>
                      </div>
                   ) : result ? (
                      <div className="h-full overflow-y-auto">
                         <p className="text-lg text-white leading-relaxed whitespace-pre-wrap">
                            {result.translatedText}
                         </p>
                         {result.transcribedText && (inputMode !== 'text') && (
                            <div className="mt-8 pt-4 border-t border-slate-700/50">
                               <p className="text-xs text-slate-500 uppercase tracking-wider mb-2">Original Content Transcription</p>
                               <p className="text-sm text-slate-400 italic">
                                  "{result.transcribedText}"
                               </p>
                            </div>
                         )}
                      </div>
                   ) : (
                      <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-8">
                         <Bot size={48} className="mb-4 opacity-20" />
                         <p className="mb-2">Translation output</p>
                         <p className="text-sm text-slate-700">Select a mode, provide content, and click Translate.</p>
                      </div>
                   )}
                </div>
              </div>
            </div>

          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  Mic,
  FileIcon
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');

  // Generic Media State (Image, PDF, Audio)
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);

  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);

  // History with LocalStorage Persistence
  const [history, setHistory] = useState<TranslationHistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('polyglot_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load history", e);
      return [];
    }
  });

  // Save history whenever it changes
  useEffect(() => {
    localStorage.setItem('polyglot_history', JSON.stringify(history));
  }, [history]);

  const [showMobileHistory, setShowMobileHistory] = useState(false);

  // Live Session State
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Extract base64 data (remove data:xxx;base64, prefix)
        const base64Data = base64String.split(',')[1];

        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = (inputMode !== 'text' && selectedMedia)
        ? { data: selectedMedia.base64, mimeType: selectedMedia.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);

      // Add to history
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: inputMode,
        preview: inputMode === 'text' ? inputText : selectedMedia?.name || 'Media File'
      };

      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error("Translation failed", error);
      alert("Something went wrong with the translation service. Please check your API Key or try again.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    if (item.type === 'live_session') return; // Cannot reload live session

    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });

    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);

    // Reset current view based on history type
    setInputMode(item.type as InputMode);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedMedia(null);
    } else {
      // We can't easily restore the file blob from history in this simple app, 
      // so we switch to text mode showing the transcription
      setInputMode('text');
      setInputText(item.transcribedText || "[Original file content not available, showing transcription]");
      setSelectedMedia(null); 
    }

    setShowMobileHistory(false);
  };

  const renderInputPreview = () => {
    if (!selectedMedia) return null;

    if (inputMode === 'image') {
      return (
        <img 
          src={selectedMedia.url} 
          alt="Upload preview" 
          className="max-h-64 object-contain mb-4 rounded shadow-lg" 
        />
      );
    } 

    if (inputMode === 'document') {
      return (
        <div className="flex flex-col items-center justify-center p-8 text-slate-300">
           <FileIcon size={64} className="mb-4 text-primary" />
           <p className="font-medium text-lg">{selectedMedia.name}</p>
           <p className="text-sm text-slate-500 uppercase mt-2">PDF / Text Document</p>
        </div>
      );
    }

    if (inputMode === 'audio_file') {
       return (
         <div className="flex flex-col items-center justify-center p-8 w-full max-w-md">
            <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 border border-slate-600">
               <Music size={32} className="text-accent" />
            </div>
            <p className="font-medium text-lg mb-4">{selectedMedia.name}</p>
            <audio controls src={selectedMedia.url} className="w-full" />
         </div>
       );
    }

    return null;
  };

  const getAcceptType = () => {
    switch (inputMode) {
      case 'image': return 'image/*';
      case 'document': return '.pdf,.txt';
      case 'audio_file': return 'audio/*';
      default: return '*/*';
    }
  };

  return (
    <div className="min-h-screen flex bg-background text-slate-200 overflow-hidden font-sans">

      {/* Live Session Overlay */}
      {isLiveSessionOpen && (
        <LiveSession 
          targetLanguage={targetLanguage} 
          onClose={() => setIsLiveSessionOpen(false)} 
        />
      )}

      {/* Sidebar (Desktop) */}
      <HistorySidebar 
        history={history} 
        onClearHistory={() => setHistory([])} 
        onSelectHistoryItem={loadHistoryItem}
      />

      {/* Mobile History Drawer */}
      {showMobileHistory && (
        <div className="fixed inset-0 z-40 lg:hidden flex">
          <div className="w-64 h-full bg-surface shadow-2xl relative">
            <button 
              onClick={() => setShowMobileHistory(false)}
              className="absolute top-4 right-4 text-slate-400"
            >
              <X size={20} />
            </button>
            <HistorySidebar 
               history={history} 
               onClearHistory={() => setHistory([])} 
               onSelectHistoryItem={loadHistoryItem}
            />
          </div>
          <div className="flex-1 bg-black/50 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)}></div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto w-full relative z-0">
        {/* Header */}
        <header className="h-16 border-b border-slate-700 flex items-center justify-between px-6 bg-surface/50 backdrop-blur sticky top-0 z-20">
          <div className="flex items-center gap-3">
            <button className="lg:hidden text-slate-400 hover:text-white" onClick={() => setShowMobileHistory(true)}>
              <Menu size={24} />
            </button>
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-violet-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Sparkles size={18} className="text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              Polyglot AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-xs font-mono text-slate-500 hidden md:block">
                Powered by Gemini 3
             </div>
          </div>
        </header>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full flex flex-col gap-6">

          {/* Controls Bar */}
          <div className="bg-surface border border-slate-700 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-lg">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <span className="text-sm font-medium text-slate-400">Auto Detect</span>
              <ArrowRightLeft className="text-slate-600" size={16} />
              <LanguageSelector 
                selectedLanguage={targetLanguage}
                onSelectLanguage={setTargetLanguage}
              />
            </div>

            <button
              onClick={handleTranslate}
              disabled={isTranslating || (inputMode === 'text' ? !inputText : !selectedMedia)}
              className="w-full md:w-auto px-8 py-2.5 bg-primary hover:bg-blue-600 disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed text-white font-semibold rounded-lg shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"
            >
              {isTranslating ? (
                <>
                  <Loader2 size={18} className="animate-spin" /> Translating...
                </>
              ) : (
                <>
                  <Bot size={18} /> Translate
                </>
              )}
            </button>
          </div>

          {/* Translation Area */}
          <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[400px]">

            {/* INPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden focus-within:ring-2 focus-within:ring-primary/50 transition-all relative group">
                {/* Panel Header (Toolbar) */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-2 bg-slate-900/30 overflow-x-auto">
                  <div className="flex items-center gap-1">
                    {[
                      { id: 'text', icon: FileText, label: 'Text' },
                      { id: 'image', icon: ImageIcon, label: 'Image' },
                      { id: 'document', icon: FileIcon, label: 'Doc' },
                      { id: 'audio_file', icon: Music, label: 'Audio' },
                    ].map((mode) => (
                      <button
                        key={mode.id}
                        onClick={() => {
                           setInputMode(mode.id as InputMode);
                           clearMedia();
                           setInputText('');
                        }}
                        className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all ${
                           inputMode === mode.id 
                             ? 'bg-slate-700 text-white shadow-sm' 
                             : 'text-slate-400 hover:text-white hover:bg-slate-800'
                        }`}
                      >
                         <mode.icon size={16} />
                         <span className="hidden sm:inline">{mode.label}</span>
                      </button>
                    ))}

                    <div className="w-px h-6 bg-slate-700 mx-2"></div>

                    <button
                      onClick={() => setIsLiveSessionOpen(true)}
                      className="px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all text-red-400 hover:text-red-300 hover:bg-red-500/10 border border-transparent hover:border-red-500/20"
                    >
                       <Mic size={16} />
                       <span className="hidden sm:inline font-medium">Live Voice</span>
                    </button>
                  </div>
                </div>

                {/* Input Content */}
                <div className="flex-1 relative p-4 flex flex-col">
                  {inputMode === 'text' ? (
                     <textarea
                       value={inputText}
                       onChange={(e) => setInputText(e.target.value)}
                       placeholder="Type text to translate..."
                       className="w-full h-full bg-transparent border-none outline-none resize-none text-slate-200 placeholder-slate-600 leading-relaxed text-lg"
                       spellCheck={false}
                     />
                  ) : (
                    // Media Upload Area
                    <div className="flex-1 flex flex-col items-center justify-center relative">
                       {selectedMedia ? (
                          <div className="w-full h-full flex flex-col items-center justify-center relative bg-black/20 rounded-lg border border-dashed border-slate-700 p-4">
                             {renderInputPreview()}
                             <button 
                               onClick={clearMedia}
                               className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
                             >
                               <X size={14} />
                             </button>
                             <div className="text-xs text-slate-500 font-mono mt-2">Ready to translate</div>
                          </div>
                       ) : (
                          <div 
                             className="w-full h-full border-2 border-dashed border-slate-700 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-primary/50 hover:bg-slate-800/30 transition-all group"
                             onClick={() => fileInputRef.current?.click()}
                          >
                             <input 
                               type="file" 
                               accept={getAcceptType()} 
                               className="hidden" 
                               ref={fileInputRef}
                               onChange={handleFileUpload}
                             />
                             <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                                <Upload size={28} className="text-slate-400 group-hover:text-primary" />
                             </div>
                             <p className="text-slate-400 font-medium">Click to upload {inputMode.replace('_', ' ')}</p>
                             <p className="text-xs text-slate-600 mt-2">
                                {inputMode === 'image' && 'JPG, PNG, WEBP'}
                                {inputMode === 'document' && 'PDF, TXT'}
                                {inputMode === 'audio_file' && 'MP3, WAV, M4A'}
                             </p>
                          </div>
                       )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* OUTPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden relative">
                {/* Panel Header */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-4 bg-slate-900/30">
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Target</span>
                    {result && (
                       <span className="px-2 py-0.5 bg-primary/20 text-primary text-xs rounded-full border border-primary/20">
                          Detected: {result.detectedSourceLanguage}
                       </span>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => result && handleCopy(result.translatedText)}
                      className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                      disabled={!result}
                      title="Copy Translation"
                    >
                      <Copy size={16} />
                    </button>
                  </div>
                </div>

                {/* Output Content */}
                <div className="flex-1 p-4 relative bg-slate-900/20">
                   {isTranslating ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-3">
                         <div className="relative">
                            <div className="w-12 h-12 rounded-full border-4 border-slate-700 border-t-primary animate-spin"></div>
                            <Bot className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-400" size={20} />
                         </div>
                         <p className="text-sm animate-pulse">AI is analyzing & translating...</p>
                      </div>
                   ) : result ? (
                      <div className="h-full overflow-y-auto">
                         <p className="text-lg text-white leading-relaxed whitespace-pre-wrap">
                            {result.translatedText}
                         </p>
                         {result.transcribedText && (inputMode !== 'text') && (
                            <div className="mt-8 pt-4 border-t border-slate-700/50">
                               <p className="text-xs text-slate-500 uppercase tracking-wider mb-2">Original Content Transcription</p>
                               <p className="text-sm text-slate-400 italic">
                                  "{result.transcribedText}"
                               </p>
                            </div>
                         )}
                      </div>
                   ) : (
                      <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-8">
                         <Bot size={48} className="mb-4 opacity-20" />
                         <p className="mb-2">Translation output</p>
                         <p className="text-sm text-slate-700">Select a mode, provide content, and click Translate.</p>
                      </div>
                   )}
                </div>
              </div>
            </div>

          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Clock, Trash2, Image as ImageIcon, Type, ArrowRight, Search, FileText, Music } from 'lucide-react';
import { TranslationHistoryItem, InputMode } from '../types';

interface HistorySidebarProps {
  history: TranslationHistoryItem[];
  onClearHistory: () => void;
  onSelectHistoryItem: (item: TranslationHistoryItem) => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onClearHistory, onSelectHistoryItem }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = useMemo(() => {
    if (!searchTerm.trim()) return history;

    const lowerTerm = searchTerm.toLowerCase();

    return history.filter(item => {
      // Search in Source text (transcription)
      const inSource = item.transcribedText?.toLowerCase().includes(lowerTerm);
      // Search in Translated text
      const inTranslation = item.translatedText.toLowerCase().includes(lowerTerm);
      // Search in Target Language name
      const inLanguage = item.targetLanguage.toLowerCase().includes(lowerTerm);
      // Search in detected source language
      const inDetected = item.detectedSourceLanguage.toLowerCase().includes(lowerTerm);

      return inSource || inTranslation || inLanguage || inDetected;
    });
  }, [history, searchTerm]);

  const getIconForType = (type: string) => {
    switch (type as InputMode | 'live_session') {
      case 'image': return <ImageIcon size={10} />;
      case 'document': return <FileText size={10} />;
      case 'audio_file': return <Music size={10} />;
      default: return <Type size={10} />;
    }
  };

  return (
    <div className="h-full flex flex-col bg-surface border-r border-slate-700 w-80 fixed md:relative z-10 hidden lg:flex">
      {/* Header */}
      <div className="p-5 border-b border-slate-700 flex justify-between items-center bg-surface">
        <div className="flex items-center gap-2 text-white">
          <Clock size={18} className="text-primary" />
          <h2 className="font-semibold">History</h2>
        </div>
        {history.length > 0 && (
          <button 
            onClick={onClearHistory}
            className="text-xs text-red-400 hover:text-red-300 transition-colors flex items-center gap-1"
          >
            <Trash2 size={12} /> Clear
          </button>
        )}
      </div>

      {/* Search Bar */}
      <div className="p-3 border-b border-slate-700 bg-slate-900/30">
         <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
            <input 
               type="text" 
               placeholder="Search translations..."
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-slate-800 text-slate-200 text-sm rounded-lg pl-9 pr-3 py-2 border border-slate-700 focus:border-primary outline-none placeholder-slate-600 transition-colors"
            />
         </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto p-3 space-y-2">
        {filteredHistory.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-secondary text-sm">
            {searchTerm ? (
               <>
                 <Search size={24} className="mb-2 opacity-20" />
                 <p>No matches found</p>
               </>
            ) : (
               <>
                  <Clock size={32} className="mb-2 opacity-20" />
                  <p>No recent history</p>
               </>
            )}
          </div>
        ) : (
          filteredHistory.map((item) => (
            <button
              key={item.id}
              onClick={() => onSelectHistoryItem(item)}
              className="w-full text-left bg-slate-800/50 hover:bg-slate-800 border border-slate-700 hover:border-slate-600 rounded-lg p-3 transition-all group"
            >
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-medium text-secondary bg-slate-900 px-2 py-0.5 rounded flex items-center gap-1">
                  {getIconForType(item.type)}
                  {item.detectedSourceLanguage} <ArrowRight size={10} /> {item.targetLanguage}
                </span>
                <span className="text-[10px] text-slate-500">
                  {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <p className="text-sm text-slate-300 line-clamp-2 mb-1 font-medium break-words">
                {item.transcribedText || "Image Content"}
              </p>
              <p className="text-xs text-secondary line-clamp-1 break-words">
                {item.translatedText}
              </p>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

export default HistorySidebar;

import React, { useMemo, useState } from 'react';
import { Clock, Trash2, Image as ImageIcon, Type, ArrowRight, Search, FileText, Music } from 'lucide-react';
import { TranslationHistoryItem, InputMode } from '../types';

interface HistorySidebarProps {
  history: TranslationHistoryItem[];
  onClearHistory: () => void;
  onSelectHistoryItem: (item: TranslationHistoryItem) => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onClearHistory, onSelectHistoryItem }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = useMemo(() => {
    if (!searchTerm.trim()) return history;

    const lowerTerm = searchTerm.toLowerCase();

    return history.filter(item => {
      // Search in Source text (transcription)
      const inSource = item.transcribedText?.toLowerCase().includes(lowerTerm);
      // Search in Translated text
      const inTranslation = item.translatedText.toLowerCase().includes(lowerTerm);
      // Search in Target Language name
      const inLanguage = item.targetLanguage.toLowerCase().includes(lowerTerm);
      // Search in detected source language
      const inDetected = item.detectedSourceLanguage.toLowerCase().includes(lowerTerm);

      return inSource || inTranslation || inLanguage || inDetected;
    });
  }, [history, searchTerm]);

  const getIconForType = (type: string) => {
    switch (type as InputMode | 'live_session') {
      case 'image': return <ImageIcon size={10} />;
      case 'document': return <FileText size={10} />;
      case 'audio_file': return <Music size={10} />;
      default: return <Type size={10} />;
    }
  };

  return (
    <div className="h-full flex flex-col bg-surface border-r border-slate-700 w-full">
      {/* Header */}
      <div className="p-5 border-b border-slate-700 flex justify-between items-center bg-surface shrink-0">
        <div className="flex items-center gap-2 text-white">
          <Clock size={18} className="text-primary" />
          <h2 className="font-semibold">History</h2>
        </div>
        {history.length > 0 && (
          <button 
            onClick={onClearHistory}
            className="text-xs text-red-400 hover:text-red-300 transition-colors flex items-center gap-1"
          >
            <Trash2 size={12} /> Clear
          </button>
        )}
      </div>

      {/* Search Bar */}
      <div className="p-3 border-b border-slate-700 bg-slate-900/30 shrink-0">
         <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
            <input 
               type="text" 
               placeholder="Search translations..."
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-slate-800 text-slate-200 text-sm rounded-lg pl-9 pr-3 py-2 border border-slate-700 focus:border-primary outline-none placeholder-slate-600 transition-colors"
            />
         </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto p-3 space-y-2">
        {filteredHistory.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-secondary text-sm">
            {searchTerm ? (
               <>
                 <Search size={24} className="mb-2 opacity-20" />
                 <p>No matches found</p>
               </>
            ) : (
               <>
                  <Clock size={32} className="mb-2 opacity-20" />
                  <p>No recent history</p>
               </>
            )}
          </div>
        ) : (
          filteredHistory.map((item) => (
            <button
              key={item.id}
              onClick={() => onSelectHistoryItem(item)}
              className="w-full text-left bg-slate-800/50 hover:bg-slate-800 border border-slate-700 hover:border-slate-600 rounded-lg p-3 transition-all group"
            >
              <div className="flex items-center justify-between mb-2">
                <span className="text-xs font-medium text-secondary bg-slate-900 px-2 py-0.5 rounded flex items-center gap-1">
                  {getIconForType(item.type)}
                  {item.detectedSourceLanguage} <ArrowRight size={10} /> {item.targetLanguage}
                </span>
                <span className="text-[10px] text-slate-500">
                  {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <p className="text-sm text-slate-300 line-clamp-2 mb-1 font-medium break-words">
                {item.transcribedText || "Image Content"}
              </p>
              <p className="text-xs text-secondary line-clamp-1 break-words">
                {item.translatedText}
              </p>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

export default HistorySidebar;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  Mic,
  FileIcon
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  // State
  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');

  // Generic Media State (Image, PDF, Audio)
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);

  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);

  // History with LocalStorage Persistence
  const [history, setHistory] = useState<TranslationHistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('polyglot_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load history", e);
      return [];
    }
  });

  // Save history whenever it changes
  useEffect(() => {
    localStorage.setItem('polyglot_history', JSON.stringify(history));
  }, [history]);

  const [showMobileHistory, setShowMobileHistory] = useState(false);

  // Live Session State
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Handlers
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        // Extract base64 data (remove data:xxx;base64, prefix)
        const base64Data = base64String.split(',')[1];

        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = (inputMode !== 'text' && selectedMedia)
        ? { data: selectedMedia.base64, mimeType: selectedMedia.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);

      // Add to history
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: inputMode,
        preview: inputMode === 'text' ? inputText : selectedMedia?.name || 'Media File'
      };

      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error("Translation failed", error);
      alert("Something went wrong with the translation service. Please check your API Key or try again.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    if (item.type === 'live_session') return; // Cannot reload live session

    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });

    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);

    // Reset current view based on history type
    setInputMode(item.type as InputMode);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedMedia(null);
    } else {
      // We can't easily restore the file blob from history in this simple app, 
      // so we switch to text mode showing the transcription
      setInputMode('text');
      setInputText(item.transcribedText || "[Original file content not available, showing transcription]");
      setSelectedMedia(null); 
    }

    setShowMobileHistory(false);
  };

  const renderInputPreview = () => {
    if (!selectedMedia) return null;

    if (inputMode === 'image') {
      return (
        <img 
          src={selectedMedia.url} 
          alt="Upload preview" 
          className="max-h-64 object-contain mb-4 rounded shadow-lg" 
        />
      );
    } 

    if (inputMode === 'document') {
      return (
        <div className="flex flex-col items-center justify-center p-8 text-slate-300">
           <FileIcon size={64} className="mb-4 text-primary" />
           <p className="font-medium text-lg">{selectedMedia.name}</p>
           <p className="text-sm text-slate-500 uppercase mt-2">PDF / Text Document</p>
        </div>
      );
    }

    if (inputMode === 'audio_file') {
       return (
         <div className="flex flex-col items-center justify-center p-8 w-full max-w-md">
            <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 border border-slate-600">
               <Music size={32} className="text-accent" />
            </div>
            <p className="font-medium text-lg mb-4">{selectedMedia.name}</p>
            <audio controls src={selectedMedia.url} className="w-full" />
         </div>
       );
    }

    return null;
  };

  const getAcceptType = () => {
    switch (inputMode) {
      case 'image': return 'image/*';
      case 'document': return '.pdf,.txt';
      case 'audio_file': return 'audio/*';
      default: return '*/*';
    }
  };

  return (
    <div className="min-h-screen flex bg-background text-slate-200 overflow-hidden font-sans">

      {/* Live Session Overlay */}
      {isLiveSessionOpen && (
        <LiveSession 
          targetLanguage={targetLanguage} 
          onClose={() => setIsLiveSessionOpen(false)} 
        />
      )}

      {/* Sidebar (Desktop) - Visible on md and up */}
      <div className="hidden md:flex w-80 h-full flex-col relative z-10 shrink-0">
        <HistorySidebar 
          history={history} 
          onClearHistory={() => setHistory([])} 
          onSelectHistoryItem={loadHistoryItem}
        />
      </div>

      {/* Mobile History Drawer - Visible on small screens */}
      {showMobileHistory && (
        <div className="fixed inset-0 z-40 md:hidden flex">
          <div className="w-72 h-full bg-surface shadow-2xl relative">
            <button 
              onClick={() => setShowMobileHistory(false)}
              className="absolute top-4 right-4 text-slate-400 z-50 hover:text-white"
            >
              <X size={20} />
            </button>
            <HistorySidebar 
               history={history} 
               onClearHistory={() => setHistory([])} 
               onSelectHistoryItem={loadHistoryItem}
            />
          </div>
          <div className="flex-1 bg-black/50 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)}></div>
        </div>
      )}

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-y-auto w-full relative z-0">
        {/* Header */}
        <header className="h-16 border-b border-slate-700 flex items-center justify-between px-6 bg-surface/50 backdrop-blur sticky top-0 z-20 shrink-0">
          <div className="flex items-center gap-3">
            <button className="md:hidden text-slate-400 hover:text-white" onClick={() => setShowMobileHistory(true)}>
              <Menu size={24} />
            </button>
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-500 to-violet-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <Sparkles size={18} className="text-white" />
            </div>
            <h1 className="text-lg font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
              Polyglot AI
            </h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-xs font-mono text-slate-500 hidden lg:block">
                Powered by Gemini 3
             </div>
          </div>
        </header>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full flex flex-col gap-6">

          {/* Controls Bar */}
          <div className="bg-surface border border-slate-700 rounded-xl p-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-lg shrink-0">
            <div className="flex items-center gap-4 w-full md:w-auto">
              <span className="text-sm font-medium text-slate-400 whitespace-nowrap">Auto Detect</span>
              <ArrowRightLeft className="text-slate-600 shrink-0" size={16} />
              <LanguageSelector 
                selectedLanguage={targetLanguage}
                onSelectLanguage={setTargetLanguage}
              />
            </div>

            <button
              onClick={handleTranslate}
              disabled={isTranslating || (inputMode === 'text' ? !inputText : !selectedMedia)}
              className="w-full md:w-auto px-8 py-2.5 bg-primary hover:bg-blue-600 disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed text-white font-semibold rounded-lg shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2"
            >
              {isTranslating ? (
                <>
                  <Loader2 size={18} className="animate-spin" /> Translating...
                </>
              ) : (
                <>
                  <Bot size={18} /> Translate
                </>
              )}
            </button>
          </div>

          {/* Translation Area */}
          <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[400px]">

            {/* INPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden focus-within:ring-2 focus-within:ring-primary/50 transition-all relative group">
                {/* Panel Header (Toolbar) */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-2 bg-slate-900/30 overflow-x-auto shrink-0">
                  <div className="flex items-center gap-1">
                    {[
                      { id: 'text', icon: FileText, label: 'Text' },
                      { id: 'image', icon: ImageIcon, label: 'Image' },
                      { id: 'document', icon: FileIcon, label: 'Doc' },
                      { id: 'audio_file', icon: Music, label: 'Audio' },
                    ].map((mode) => (
                      <button
                        key={mode.id}
                        onClick={() => {
                           setInputMode(mode.id as InputMode);
                           clearMedia();
                           setInputText('');
                        }}
                        className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all whitespace-nowrap ${
                           inputMode === mode.id 
                             ? 'bg-slate-700 text-white shadow-sm' 
                             : 'text-slate-400 hover:text-white hover:bg-slate-800'
                        }`}
                      >
                         <mode.icon size={16} />
                         <span className="hidden sm:inline">{mode.label}</span>
                      </button>
                    ))}

                    <div className="w-px h-6 bg-slate-700 mx-2 shrink-0"></div>

                    <button
                      onClick={() => setIsLiveSessionOpen(true)}
                      className="px-3 py-1.5 rounded-lg flex items-center gap-2 text-sm transition-all text-red-400 hover:text-red-300 hover:bg-red-500/10 border border-transparent hover:border-red-500/20 whitespace-nowrap"
                    >
                       <Mic size={16} />
                       <span className="hidden sm:inline font-medium">Live Voice</span>
                    </button>
                  </div>
                </div>

                {/* Input Content */}
                <div className="flex-1 relative p-4 flex flex-col">
                  {inputMode === 'text' ? (
                     <textarea
                       value={inputText}
                       onChange={(e) => setInputText(e.target.value)}
                       placeholder="Type text to translate..."
                       className="w-full h-full bg-transparent border-none outline-none resize-none text-slate-200 placeholder-slate-600 leading-relaxed text-lg"
                       spellCheck={false}
                     />
                  ) : (
                    // Media Upload Area
                    <div className="flex-1 flex flex-col items-center justify-center relative">
                       {selectedMedia ? (
                          <div className="w-full h-full flex flex-col items-center justify-center relative bg-black/20 rounded-lg border border-dashed border-slate-700 p-4">
                             {renderInputPreview()}
                             <button 
                               onClick={clearMedia}
                               className="absolute top-2 right-2 p-1 bg-black/50 text-white rounded-full hover:bg-red-500 transition-colors"
                             >
                               <X size={14} />
                             </button>
                             <div className="text-xs text-slate-500 font-mono mt-2">Ready to translate</div>
                          </div>
                       ) : (
                          <div 
                             className="w-full h-full border-2 border-dashed border-slate-700 rounded-xl flex flex-col items-center justify-center cursor-pointer hover:border-primary/50 hover:bg-slate-800/30 transition-all group"
                             onClick={() => fileInputRef.current?.click()}
                          >
                             <input 
                               type="file" 
                               accept={getAcceptType()} 
                               className="hidden" 
                               ref={fileInputRef}
                               onChange={handleFileUpload}
                             />
                             <div className="w-16 h-16 rounded-full bg-slate-800 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                                <Upload size={28} className="text-slate-400 group-hover:text-primary" />
                             </div>
                             <p className="text-slate-400 font-medium">Click to upload {inputMode.replace('_', ' ')}</p>
                             <p className="text-xs text-slate-600 mt-2">
                                {inputMode === 'image' && 'JPG, PNG, WEBP'}
                                {inputMode === 'document' && 'PDF, TXT'}
                                {inputMode === 'audio_file' && 'MP3, WAV, M4A'}
                             </p>
                          </div>
                       )}
                    </div>
                  )}
                </div>
              </div>
            </div>

            {/* OUTPUT PANEL */}
            <div className="flex flex-col gap-4">
              <div className="bg-surface border border-slate-700 rounded-2xl flex-1 flex flex-col shadow-xl overflow-hidden relative">
                {/* Panel Header */}
                <div className="h-14 border-b border-slate-700/50 flex items-center justify-between px-4 bg-slate-900/30 shrink-0">
                  <div className="flex items-center gap-3">
                    <span className="text-xs font-medium text-slate-400 uppercase tracking-wider">Target</span>
                    {result && (
                       <span className="px-2 py-0.5 bg-primary/20 text-primary text-xs rounded-full border border-primary/20">
                          Detected: {result.detectedSourceLanguage}
                       </span>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <button 
                      onClick={() => result && handleCopy(result.translatedText)}
                      className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white transition-colors"
                      disabled={!result}
                      title="Copy Translation"
                    >
                      <Copy size={16} />
                    </button>
                  </div>
                </div>

                {/* Output Content */}
                <div className="flex-1 p-4 relative bg-slate-900/20">
                   {isTranslating ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 gap-3">
                         <div className="relative">
                            <div className="w-12 h-12 rounded-full border-4 border-slate-700 border-t-primary animate-spin"></div>
                            <Bot className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 text-slate-400" size={20} />
                         </div>
                         <p className="text-sm animate-pulse">AI is analyzing & translating...</p>
                      </div>
                   ) : result ? (
                      <div className="h-full overflow-y-auto">
                         <p className="text-lg text-white leading-relaxed whitespace-pre-wrap">
                            {result.translatedText}
                         </p>
                         {result.transcribedText && (inputMode !== 'text') && (
                            <div className="mt-8 pt-4 border-t border-slate-700/50">
                               <p className="text-xs text-slate-500 uppercase tracking-wider mb-2">Original Content Transcription</p>
                               <p className="text-sm text-slate-400 italic">
                                  "{result.transcribedText}"
                               </p>
                            </div>
                         )}
                      </div>
                   ) : (
                      <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-8">
                         <Bot size={48} className="mb-4 opacity-20" />
                         <p className="mb-2">Translation output</p>
                         <p className="text-sm text-slate-700">Select a mode, provide content, and click Translate.</p>
                      </div>
                   )}
                </div>
              </div>
            </div>

          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Clock, Trash2, Image as ImageIcon, Type, ArrowRight, Search, FileText, Music, History } from 'lucide-react';
import { TranslationHistoryItem, InputMode } from '../types';

interface HistorySidebarProps {
  history: TranslationHistoryItem[];
  onClearHistory: () => void;
  onSelectHistoryItem: (item: TranslationHistoryItem) => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onClearHistory, onSelectHistoryItem }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = useMemo(() => {
    if (!searchTerm.trim()) return history;

    const lowerTerm = searchTerm.toLowerCase();

    return history.filter(item => {
      const inSource = item.transcribedText?.toLowerCase().includes(lowerTerm);
      const inTranslation = item.translatedText.toLowerCase().includes(lowerTerm);
      const inLanguage = item.targetLanguage.toLowerCase().includes(lowerTerm);
      const inDetected = item.detectedSourceLanguage.toLowerCase().includes(lowerTerm);
      return inSource || inTranslation || inLanguage || inDetected;
    });
  }, [history, searchTerm]);

  const getIconForType = (type: string) => {
    switch (type as InputMode | 'live_session') {
      case 'image': return <ImageIcon size={12} />;
      case 'document': return <FileText size={12} />;
      case 'audio_file': return <Music size={12} />;
      default: return <Type size={12} />;
    }
  };

  return (
    <div className="h-full flex flex-col w-full bg-black/20 backdrop-blur-xl border-r border-white/5">
      {/* Header */}
      <div className="p-6 pb-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2 text-white/90">
          <History size={16} className="text-primary" />
          <h2 className="text-sm font-medium tracking-wide uppercase text-slate-400">Recent Activity</h2>
        </div>
        {history.length > 0 && (
          <button 
            onClick={onClearHistory}
            className="p-1.5 rounded-md text-slate-500 hover:text-red-400 hover:bg-white/5 transition-all"
          >
            <Trash2 size={14} />
          </button>
        )}
      </div>

      {/* Search Bar */}
      <div className="px-6 pb-4 shrink-0">
         <div className="relative group">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-primary transition-colors" />
            <input 
               type="text" 
               placeholder="Search..."
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-white/5 text-slate-200 text-xs rounded-xl pl-9 pr-3 py-2.5 border border-transparent focus:border-white/10 focus:bg-white/10 outline-none transition-all placeholder-slate-600"
            />
         </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
        {filteredHistory.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-slate-600 text-xs">
            {searchTerm ? <p>No matches found</p> : <p>History is empty</p>}
          </div>
        ) : (
          filteredHistory.map((item) => (
            <button
              key={item.id}
              onClick={() => onSelectHistoryItem(item)}
              className="w-full text-left bg-white/5 hover:bg-white/10 border border-transparent hover:border-white/5 rounded-xl p-3 transition-all group relative overflow-hidden"
            >
              <div className="flex items-center justify-between mb-2">
