  }, [searchTerm]);

  return (
    <div className="relative w-full md:w-56" ref={containerRef}>
      {label && <label className="block text-[10px] font-medium text-slate-500 uppercase tracking-widest mb-2">{label}</label>}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between bg-white/5 hover:bg-white/10 border border-white/5 hover:border-white/10 text-white px-3 py-2 rounded-xl transition-all duration-200 group"
      >
        <span className="flex items-center gap-2.5">
          <span className="w-5 h-5 flex items-center justify-center rounded-full bg-white/5 text-xs shadow-inner">
            {selectedLanguage.flag}
          </span>
          <span className="text-sm font-medium text-slate-200">{selectedLanguage.name}</span>
        </span>
        <ChevronDown size={14} className={`text-slate-500 group-hover:text-slate-300 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-[#0A0A0A] border border-white/10 rounded-xl shadow-2xl shadow-black/50 max-h-80 flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-100 origin-top">
          <div className="p-2 border-b border-white/5 sticky top-0 bg-[#0A0A0A]/95 backdrop-blur-sm">
            <div className="relative">
              <Search size={12} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
              <input
                type="text"
                placeholder="Search..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                autoFocus
                className="w-full bg-white/5 text-white text-xs rounded-lg pl-8 pr-3 py-2 outline-none border border-transparent focus:border-primary/50 placeholder-slate-600"
              />
            </div>
          </div>

          <div className="overflow-y-auto flex-1 p-1 custom-scrollbar">
            {filteredLanguages.length === 0 ? (
              <div className="p-4 text-xs text-slate-500 text-center">No results</div>
            ) : (
              filteredLanguages.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => {
                    onSelectLanguage(lang);
                    setIsOpen(false);
                    setSearchTerm('');
                  }}
                  className={`w-full text-left px-3 py-2 rounded-lg flex items-center justify-between hover:bg-white/5 transition-colors group ${
                    selectedLanguage.code === lang.code ? 'bg-primary/10' : ''
                  }`}
                >
                  <span className="flex items-center gap-3">
                    <span className="text-base leading-none">{lang.flag}</span>
                    <span className={`text-sm ${selectedLanguage.code === lang.code ? 'text-primary' : 'text-slate-300 group-hover:text-white'}`}>
                      {lang.name}
                    </span>
                  </span>
                  {selectedLanguage.code === lang.code && (
                    <div className="w-1.5 h-1.5 rounded-full bg-primary shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
                  )}
                </button>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

