import React, { useEffect, useRef, useState } from 'react';
import { X, Mic, StopCircle, Radio, Activity } from 'lucide-react';
import { LiveServerMessage, Modality } from '@google/genai';
import { ai } from '../services/geminiService';
import { decode, decodeAudioData, createBlob } from '../utils/audioUtils';
import { Language } from '../types';

interface LiveSessionProps {
  targetLanguage: Language;
  onClose: () => void;
}

const LiveSession: React.FC<LiveSessionProps> = ({ targetLanguage, onClose }) => {
  const [isConnected, setIsConnected] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [transcripts, setTranscripts] = useState<{ source: 'user' | 'model'; text: string }[]>([]);
  const [currentInput, setCurrentInput] = useState('');
  const [currentOutput, setCurrentOutput] = useState('');

  // Audio Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceNodeRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    startSession();
    return () => stopSession();
  }, [targetLanguage]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [transcripts, currentInput, currentOutput]);

  const startSession = async () => {
    try {
      setIsConnected(false);
      setError(null);

      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      inputAudioContextRef.current = new AudioContextClass({ sampleRate: 16000 });
      outputAudioContextRef.current = new AudioContextClass({ sampleRate: 24000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      sessionPromiseRef.current = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setIsConnected(true);
            setupAudioInput(stream);
          },
          onmessage: handleMessage,
          onclose: () => {
             setIsConnected(false);
          },
          onerror: (e) => {
            console.error("Session error", e);
            setError("Connection failed. Please try again.");
            setIsConnected(false);
          }
        },
        config: {
          responseModalities: [Modality.AUDIO],
          inputAudioTranscription: {},
          outputAudioTranscription: {},
          systemInstruction: `You are a professional real-time translator. Listen to the user's speech. 
          1. Transcribe what they say. 
          2. Translate it into ${targetLanguage.name}. 
          3. Speak ONLY the translation out loud clearly. 
          Do not engage in conversation.`
        }
      });

    } catch (err) {
      console.error(err);
      setError("Could not access microphone or connect to AI.");
    }
  };

  const setupAudioInput = (stream: MediaStream) => {
    if (!inputAudioContextRef.current || !sessionPromiseRef.current) return;

    const ctx = inputAudioContextRef.current;
    const source = ctx.createMediaStreamSource(stream);
    const processor = ctx.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);
      sessionPromiseRef.current?.then((session) => {
        session.sendRealtimeInput({ media: pcmBlob });
      });
    };

    source.connect(processor);
    processor.connect(ctx.destination);

    scriptProcessorRef.current = processor;
    sourceNodeRef.current = source;
  };

  const handleMessage = async (message: LiveServerMessage) => {
    if (message.serverContent?.inputTranscription) {
      const text = message.serverContent.inputTranscription.text;
      setCurrentInput(prev => prev + text);
    }

    if (message.serverContent?.outputTranscription) {
      const text = message.serverContent.outputTranscription.text;
      setCurrentOutput(prev => prev + text);
    }

    if (message.serverContent?.turnComplete) {
       if (currentInput || currentOutput) {
          setTranscripts(prev => [
             ...prev, 
             ...(currentInput ? [{ source: 'user' as const, text: currentInput }] : []),
             ...(currentOutput ? [{ source: 'model' as const, text: currentOutput }] : [])
          ]);
          setCurrentInput('');
          setCurrentOutput('');
       }
    }

    const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
    if (base64Audio && outputAudioContextRef.current) {
       const ctx = outputAudioContextRef.current;
       try {
         const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);
         const source = ctx.createBufferSource();
         source.buffer = audioBuffer;
         source.connect(ctx.destination);
         nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
         source.start(nextStartTimeRef.current);
         nextStartTimeRef.current += audioBuffer.duration;
         source.onended = () => sourcesRef.current.delete(source);
         sourcesRef.current.add(source);
       } catch (e) {
         console.error("Audio decode error", e);
       }
    }

    if (message.serverContent?.interrupted) {
       sourcesRef.current.forEach(source => source.stop());
       sourcesRef.current.clear();
       nextStartTimeRef.current = 0;
       setCurrentInput('');
       setCurrentOutput('');
    }
  };

  const stopSession = () => {
    sessionPromiseRef.current?.then(session => session.close());
    streamRef.current?.getTracks().forEach(track => track.stop());
    scriptProcessorRef.current?.disconnect();
    sourceNodeRef.current?.disconnect();
    inputAudioContextRef.current?.close();
    outputAudioContextRef.current?.close();
  };

  return (
    <div className="fixed inset-0 z-50 flex flex-col bg-black/90 backdrop-blur-2xl text-white font-sans animate-in fade-in duration-300">

      {/* Top Bar */}
      <div className="h-20 flex items-center justify-between px-8 border-b border-white/5 bg-black/20">
        <div className="flex items-center gap-4">
          <div className="relative">
             <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500 shadow-[0_0_12px_rgba(34,197,94,0.8)]' : 'bg-red-500'}`} />
             {isConnected && <div className="absolute inset-0 bg-green-500 rounded-full animate-ping opacity-50" />}
          </div>
          <div>
            <h2 className="font-semibold text-lg tracking-wide">Live Translation</h2>
            <div className="flex items-center gap-2 text-xs text-slate-400">
              <span>Auto-Detect</span>
              <span className="w-1 h-1 rounded-full bg-slate-600" />
              <span className="text-primary">{targetLanguage.name}</span>
            </div>
          </div>
        </div>

        <button 
          onClick={onClose} 
          className="w-10 h-10 rounded-full bg-white/5 hover:bg-white/10 flex items-center justify-center transition-all hover:rotate-90"
        >
          <X size={20} className="text-slate-400" />
        </button>
      </div>

      {/* Main Visualization Area */}
      <div className="flex-1 flex flex-col relative overflow-hidden">

        {/* Background Ambient Effect */}
        <div className="absolute inset-0 pointer-events-none flex items-center justify-center opacity-20">
           <div className={`w-[500px] h-[500px] rounded-full bg-gradient-to-r from-blue-600 to-purple-600 blur-[100px] transition-transform duration-[2000ms] ${isConnected ? 'scale-100 animate-pulse-slow' : 'scale-50'}`} />
        </div>

        {/* Transcripts Scroll */}
        <div className="flex-1 overflow-y-auto p-8 space-y-8 relative z-10 custom-scrollbar">
           {transcripts.length === 0 && !currentInput && !currentOutput && (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-600 gap-6">
                <div className="w-24 h-24 rounded-full border border-white/10 flex items-center justify-center bg-white/5">
                  <Mic size={32} className={isConnected ? "text-primary animate-pulse" : "text-slate-600"} />
                </div>
                <p className="text-sm tracking-widest uppercase">Listening for speech...</p>
             </div>
           )}

           {transcripts.map((t, i) => (
             <div key={i} className={`flex ${t.source === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
               <div className={`max-w-2xl p-6 rounded-3xl backdrop-blur-md ${
                 t.source === 'user' 
                   ? 'bg-white/5 border border-white/10 text-slate-300 rounded-tr-none' 
                   : 'bg-gradient-to-br from-indigo-600/20 to-purple-600/20 border border-indigo-500/20 text-white rounded-tl-none shadow-[0_0_30px_rgba(79,70,229,0.1)]'
               }`}>
                 <p className="text-lg font-light leading-relaxed">{t.text}</p>
                 <span className="text-[10px] uppercase tracking-widest opacity-50 mt-4 block">
                    {t.source === 'user' ? 'Original' : 'Translated'}
                 </span>
               </div>
             </div>
           ))}

           {/* Live Partials */}
           {(currentInput || currentOutput) && (
              <div className="space-y-4">
                 {currentInput && (
                   <div className="flex justify-end">
                      <div className="max-w-2xl p-6 rounded-3xl rounded-tr-none bg-white/5 border border-dashed border-white/10 text-slate-400">
                         {currentInput}
                      </div>
                   </div>
                 )}
                 {currentOutput && (
                   <div className="flex justify-start">
                      <div className="max-w-2xl p-6 rounded-3xl rounded-tl-none bg-indigo-500/10 border border-dashed border-indigo-500/30 text-indigo-200">
                         {currentOutput}
                      </div>
                   </div>
                 )}
              </div>
           )}
           <div ref={messagesEndRef} />
        </div>
      </div>

      {/* Bottom Controls */}
      <div className="h-24 border-t border-white/5 bg-black/20 flex items-center justify-center gap-6 relative z-20">
         {isConnected ? (
           <div className="flex items-center gap-4">
              <div className="flex items-center gap-1 h-8">
                 {[1,2,3,4,5].map(i => (
                    <div key={i} className="w-1 bg-primary/50 rounded-full animate-pulse" style={{ height: Math.random() * 24 + 8 + 'px', animationDuration: '0.5s' }} />
                 ))}
              </div>
              <span className="text-xs font-mono text-primary animate-pulse">LIVE PROCESSING</span>
           </div>
         ) : (
           <span className="text-xs font-mono text-red-500">DISCONNECTED</span>
         )}

         <button 
           onClick={onClose}
           className="absolute right-8 flex items-center gap-2 px-6 py-3 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-full transition-all group"
         >
           <StopCircle size={18} className="group-hover:scale-110 transition-transform" />
           <span className="text-sm font-medium">End Session</span>
         </button>
      </div>

      {error && (
        <div className="absolute top-24 left-1/2 -translate-x-1/2 px-6 py-3 bg-red-500/20 border border-red-500/30 text-red-200 rounded-full text-sm backdrop-blur-md">
          {error}
        </div>
      )}
    </div>
  );
};

export default LiveSession;

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  Mic,
  FileIcon,
  ChevronRight,
  Wand2
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);
  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);

  const [history, setHistory] = useState<TranslationHistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('polyglot_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('polyglot_history', JSON.stringify(history));
  }, [history]);

  const [showMobileHistory, setShowMobileHistory] = useState(false);
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        const base64Data = base64String.split(',')[1];
        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = (inputMode !== 'text' && selectedMedia)
        ? { data: selectedMedia.base64, mimeType: selectedMedia.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: inputMode,
        preview: inputMode === 'text' ? inputText : selectedMedia?.name || 'Media File'
      };
      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error(error);
      alert("Translation failed.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    if (item.type === 'live_session') return;
    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });
    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);
    setInputMode(item.type as InputMode);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedMedia(null);
    } else {
      setInputMode('text');
      setInputText(item.transcribedText || "[Content]");
      setSelectedMedia(null); 
    }
    setShowMobileHistory(false);
  };

  const getAcceptType = () => {
    switch (inputMode) {
      case 'image': return 'image/*';
      case 'document': return '.pdf,.txt';
      case 'audio_file': return 'audio/*';
      default: return '*/*';
    }
  };

  return (
    <div className="h-screen w-screen flex flex-col md:flex-row relative z-10 font-sans text-slate-200">

      {isLiveSessionOpen && (
        <LiveSession 
          targetLanguage={targetLanguage} 
          onClose={() => setIsLiveSessionOpen(false)} 
        />
      )}

      {/* Mobile Drawer */}
      <div className={`fixed inset-0 z-50 transform transition-transform duration-300 md:hidden ${showMobileHistory ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)} />
        <div className="relative w-80 h-full bg-surface shadow-2xl">
          <HistorySidebar 
             history={history} 
             onClearHistory={() => setHistory([])} 
             onSelectHistoryItem={loadHistoryItem}
          />
        </div>
      </div>

      {/* Desktop Sidebar */}
      <div className="hidden md:flex w-72 shrink-0 flex-col border-r border-white/5 bg-black/40 backdrop-blur-md">
        <div className="h-20 flex items-center px-6 border-b border-white/5">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center shadow-[0_0_15px_rgba(99,102,241,0.5)]">
            <Sparkles size={16} className="text-white" />
          </div>
          <span className="ml-3 font-bold text-lg tracking-tight text-white">Polyglot</span>
        </div>
        <HistorySidebar 
          history={history} 
          onClearHistory={() => setHistory([])} 
          onSelectHistoryItem={loadHistoryItem}
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Header (Mobile Only for Menu) */}
        <div className="md:hidden h-16 flex items-center justify-between px-4 border-b border-white/5 bg-black/40 backdrop-blur-md">
           <button onClick={() => setShowMobileHistory(true)}><Menu className="text-white" /></button>
           <span className="font-bold text-white">Polyglot</span>
           <div className="w-6" />
        </div>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 flex flex-col gap-6 overflow-y-auto">

          {/* Top Control Bar */}
          <div className="glass-panel rounded-2xl p-4 flex flex-col md:flex-row items-center justify-between gap-6">

             {/* Mode Selector - Capsule */}
             <div className="flex bg-black/40 p-1 rounded-xl border border-white/5 overflow-x-auto max-w-full no-scrollbar">
                {[
                  { id: 'text', icon: FileText, label: 'Text' },
                  { id: 'image', icon: ImageIcon, label: 'Image' },
                  { id: 'document', icon: FileIcon, label: 'Doc' },
                  { id: 'audio_file', icon: Music, label: 'Audio' },
                ].map((mode) => (
                  <button
                    key={mode.id}
                    onClick={() => { setInputMode(mode.id as InputMode); clearMedia(); setInputText(''); }}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                      inputMode === mode.id 
                        ? 'bg-white/10 text-white shadow-sm' 
                        : 'text-slate-400 hover:text-white hover:bg-white/5'
                    }`}
                  >
                    <mode.icon size={16} />
                    {mode.label}
                  </button>
                ))}
             </div>

             {/* Live Button */}
             <button
                onClick={() => setIsLiveSessionOpen(true)}
                className="group flex items-center gap-2 px-5 py-2.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 border border-red-500/20 rounded-xl transition-all"
              >
                <div className="relative">
                  <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
                  <div className="absolute inset-0 bg-red-500 rounded-full animate-ping opacity-50" />
                </div>
                <span className="text-sm font-medium tracking-wide">Live Voice</span>
             </button>
          </div>

          {/* Main Card Area */}
