import React, { useState, useRef, useEffect, useMemo } from 'react';
import { ChevronDown, Search, Check, Globe } from 'lucide-react';
import { Language } from '../types';
import { SUPPORTED_LANGUAGES } from '../constants';

interface LanguageSelectorProps {
  selectedLanguage: Language;
  onSelectLanguage: (lang: Language) => void;
  label?: string;
}

const LanguageSelector: React.FC<LanguageSelectorProps> = ({
  selectedLanguage,
  onSelectLanguage,
  label
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const filteredLanguages = useMemo(() => {
    return SUPPORTED_LANGUAGES.filter(lang =>
      lang.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  return (
    <div className="relative w-full md:w-56" ref={containerRef}>
      {label && <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-2">{label}</label>}

      <button
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between bg-white/5 hover:bg-white/10 border border-white/10 hover:border-white/20 text-white px-3 py-2.5 rounded-xl transition-all duration-200 group shadow-sm"
      >
        <span className="flex items-center gap-2.5">
          <span className="w-5 h-5 flex items-center justify-center rounded-full bg-white/5 text-xs shadow-inner border border-white/5">
            {selectedLanguage.flag}
          </span>
          <span className="text-sm font-medium text-white">{selectedLanguage.name}</span>
        </span>
        <ChevronDown size={14} className={`text-slate-400 group-hover:text-white transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute z-50 w-full mt-2 bg-[#121212] border border-white/10 rounded-xl shadow-2xl shadow-black max-h-80 flex flex-col overflow-hidden animate-in fade-in zoom-in-95 duration-100 origin-top ring-1 ring-white/5">
          <div className="p-2 border-b border-white/5 sticky top-0 bg-[#121212]/95 backdrop-blur-sm z-10">
            <div className="relative">
              <Search size={12} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                type="text"
                placeholder="Search language..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                autoFocus
                className="w-full bg-white/5 text-white text-xs rounded-lg pl-8 pr-3 py-2 outline-none border border-transparent focus:border-primary/50 placeholder-slate-500"
              />
            </div>
          </div>

          <div className="overflow-y-auto flex-1 p-1 custom-scrollbar">
            {filteredLanguages.length === 0 ? (
              <div className="p-4 text-xs text-slate-500 text-center">No results</div>
            ) : (
              filteredLanguages.map((lang) => (
                <button
                  key={lang.code}
                  onClick={() => {
                    onSelectLanguage(lang);
                    setIsOpen(false);
                    setSearchTerm('');
                  }}
                  className={`w-full text-left px-3 py-2 rounded-lg flex items-center justify-between hover:bg-white/10 transition-colors group ${
                    selectedLanguage.code === lang.code ? 'bg-primary/20' : ''
                  }`}
                >
                  <span className="flex items-center gap-3">
                    <span className="text-base leading-none">{lang.flag}</span>
                    <span className={`text-sm ${selectedLanguage.code === lang.code ? 'text-primary font-semibold' : 'text-slate-300 group-hover:text-white'}`}>
                      {lang.name}
                    </span>
                  </span>
                  {selectedLanguage.code === lang.code && (
                    <div className="w-1.5 h-1.5 rounded-full bg-primary shadow-[0_0_8px_rgba(99,102,241,0.6)]"></div>
                  )}
                </button>
              ))
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default LanguageSelector;

import React, { useMemo, useState } from 'react';
import { Clock, Trash2, Image as ImageIcon, Type, ArrowRight, Search, FileText, Music, History } from 'lucide-react';
import { TranslationHistoryItem, InputMode } from '../types';

interface HistorySidebarProps {
  history: TranslationHistoryItem[];
  onClearHistory: () => void;
  onSelectHistoryItem: (item: TranslationHistoryItem) => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onClearHistory, onSelectHistoryItem }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = useMemo(() => {
    if (!searchTerm.trim()) return history;

    const lowerTerm = searchTerm.toLowerCase();

    return history.filter(item => {
      const inSource = item.transcribedText?.toLowerCase().includes(lowerTerm);
      const inTranslation = item.translatedText.toLowerCase().includes(lowerTerm);
      const inLanguage = item.targetLanguage.toLowerCase().includes(lowerTerm);
      const inDetected = item.detectedSourceLanguage.toLowerCase().includes(lowerTerm);
      return inSource || inTranslation || inLanguage || inDetected;
    });
  }, [history, searchTerm]);

  const getIconForType = (type: string) => {
    switch (type as InputMode | 'live_session') {
      case 'image': return <ImageIcon size={12} />;
      case 'document': return <FileText size={12} />;
      case 'audio_file': return <Music size={12} />;
      default: return <Type size={12} />;
    }
  };

  return (
    <div className="h-full flex flex-col w-full bg-[#050505]/80 backdrop-blur-xl border-r border-white/5">
      {/* Header */}
      <div className="p-6 pb-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2 text-white/90">
          <History size={16} className="text-primary" />
          <h2 className="text-sm font-medium tracking-wide uppercase text-slate-400">Recent Activity</h2>
        </div>
        {history.length > 0 && (
          <button 
            onClick={onClearHistory}
            className="p-1.5 rounded-md text-slate-500 hover:text-red-400 hover:bg-white/5 transition-all"
          >
            <Trash2 size={14} />
          </button>
        )}
      </div>

      {/* Search Bar */}
      <div className="px-6 pb-4 shrink-0">
         <div className="relative group">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-primary transition-colors" />
            <input 
               type="text" 
               placeholder="Search..."
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-white/5 text-slate-200 text-xs rounded-xl pl-9 pr-3 py-2.5 border border-transparent focus:border-white/10 focus:bg-white/10 outline-none transition-all placeholder-slate-500"
            />
         </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-2">
        {filteredHistory.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-slate-500 text-xs">
            {searchTerm ? <p>No matches found</p> : <p>History is empty</p>}
          </div>
        ) : (
          filteredHistory.map((item) => (
            <button
              key={item.id}
              onClick={() => onSelectHistoryItem(item)}
              className="w-full text-left bg-white/5 hover:bg-white/10 border border-transparent hover:border-white/5 rounded-xl p-3 transition-all group relative overflow-hidden"
            >
              <div className="flex items-center justify-between mb-2">
                <span className="text-[10px] font-medium text-slate-400 bg-white/5 px-2 py-0.5 rounded-full flex items-center gap-1.5 border border-white/5">
                  {getIconForType(item.type)}
                  <span className="text-white/70">{item.detectedSourceLanguage}</span>
                  <ArrowRight size={8} className="text-slate-600" />
                  <span className="text-primary">{item.targetLanguage}</span>
                </span>
                <span className="text-[10px] text-slate-500 font-mono">
                  {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <p className="text-xs text-slate-300 line-clamp-2 mb-1.5 leading-relaxed opacity-80 group-hover:opacity-100">
                {item.transcribedText || "Image Content"}
              </p>
              <p className="text-xs text-indigo-300/80 line-clamp-1 italic font-light">
                {item.translatedText}
              </p>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

export default HistorySidebar;

import React, { useState, useRef, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  FileIcon,
  Wand2,
  Moon,
  Sun
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent } from './services/geminiService';

const App: React.FC = () => {
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme');
    if (saved) return saved as 'light' | 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);
  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);

  const [history, setHistory] = useState<TranslationHistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('polyglot_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('polyglot_history', JSON.stringify(history));
  }, [history]);

  const [showMobileHistory, setShowMobileHistory] = useState(false);
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        const base64Data = base64String.split(',')[1];
        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      const input = (inputMode !== 'text' && selectedMedia)
        ? { data: selectedMedia.base64, mimeType: selectedMedia.mimeType }
        : inputText;

      const translation = await translateContent(input, targetLanguage.name);

      setResult(translation);
      const newHistoryItem: TranslationHistoryItem = {
        id: Date.now().toString(),
        timestamp: Date.now(),
        detectedSourceLanguage: translation.detectedSourceLanguage,
        transcribedText: translation.transcribedText,
        translatedText: translation.translatedText,
        targetLanguage: targetLanguage.name,
        type: inputMode,
        preview: inputMode === 'text' ? inputText : selectedMedia?.name || 'Media File'
      };
      setHistory(prev => [newHistoryItem, ...prev]);

    } catch (error) {
      console.error(error);
      alert("Translation failed.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const loadHistoryItem = (item: TranslationHistoryItem) => {
    if (item.type === 'live_session') return;
    setResult({
      detectedSourceLanguage: item.detectedSourceLanguage,
      transcribedText: item.transcribedText,
      translatedText: item.translatedText
    });
    const foundLang = SUPPORTED_LANGUAGES.find(l => l.name === item.targetLanguage);
    if (foundLang) setTargetLanguage(foundLang);
    setInputMode(item.type as InputMode);

    if (item.type === 'text' && item.transcribedText) {
      setInputText(item.transcribedText);
      setSelectedMedia(null);
    } else {
      setInputMode('text');
      setInputText(item.transcribedText || "[Content]");
      setSelectedMedia(null); 
    }
    setShowMobileHistory(false);
  };

  const getAcceptType = () => {
    switch (inputMode) {
      case 'image': return 'image/*';
      case 'document': return '.pdf,.txt';
      case 'audio_file': return 'audio/*';
      default: return '*/*';
    }
  };

  return (
    <div className="min-h-screen w-full flex bg-bg-primary text-text-primary overflow-hidden font-sans transition-colors duration-300">

      {isLiveSessionOpen && (
        <LiveSession 
          targetLanguage={targetLanguage} 
          onClose={() => setIsLiveSessionOpen(false)} 
        />
      )}

      {/* Mobile Drawer */}
      <div className={`fixed inset-0 z-50 transform transition-transform duration-300 md:hidden ${showMobileHistory ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="absolute inset-0 bg-bg-primary/90 backdrop-blur-sm" onClick={() => setShowMobileHistory(false)} />
        <div className="relative w-80 h-full bg-bg-secondary border-r-3 border-border-primary shadow-brutal-lg">
          <HistorySidebar 
             history={history} 
             onClearHistory={() => setHistory([])} 
             onSelectHistoryItem={loadHistoryItem}
          />
        </div>
      </div>

      {/* Desktop Sidebar */}
      <div className="hidden md:flex w-80 shrink-0 flex-col border-r-3 border-border-primary bg-bg-secondary">
        <div className="h-24 flex items-center justify-between px-6 border-b-3 border-border-primary">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-btn-bg text-btn-text flex items-center justify-center border-2 border-btn-glow shadow-[2px_2px_0px_0px_var(--btn-border-glow)]">
              <Sparkles size={20} />
            </div>
            <span className="font-extrabold text-xl tracking-tight text-text-primary">Polyglot</span>
          </div>
        </div>
        <HistorySidebar 
          history={history} 
          onClearHistory={() => setHistory([])} 
          onSelectHistoryItem={loadHistoryItem}
        />
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col min-w-0 h-screen overflow-y-auto">

        {/* Header */}
        <header className="h-20 md:h-24 flex items-center justify-between px-6 md:px-10 border-b-3 border-border-primary bg-bg-secondary shrink-0">
           <div className="flex items-center gap-4">
             <button onClick={() => setShowMobileHistory(true)} className="md:hidden text-text-primary hover:scale-110 transition-transform">
               <Menu size={28} />
             </button>
             <h1 className="text-xl md:text-2xl font-extrabold md:hidden">Polyglot</h1>
             <div className="hidden md:flex items-center gap-2 px-4 py-2 rounded-full border-2 border-border-primary bg-accent-beige">
                <span className="w-2 h-2 rounded-full bg-btn-border-glow animate-pulse"></span>
                <span className="text-xs font-bold uppercase tracking-wider">Gemini 3.0 Active</span>
             </div>
           </div>

           <button 
             onClick={toggleTheme}
             className="w-12 h-12 rounded-full border-3 border-border-primary flex items-center justify-center hover:bg-text-primary hover:text-bg-secondary transition-all hover:-translate-y-1 hover:shadow-brutal"
           >
              {theme === 'light' ? <Moon size={24} /> : <Sun size={24} />}
           </button>
        </header>

        {/* Workspace */}
        <main className="flex-1 p-4 md:p-8 lg:p-12 max-w-[1600px] mx-auto w-full flex flex-col gap-8">

          {/* Top Control Bar */}
          <div className="bg-bg-secondary border-3 border-border-primary rounded-3xl p-4 md:p-6 flex flex-col xl:flex-row items-center justify-between gap-6 shadow-brutal">

             {/* Mode Selector */}
             <div className="flex w-full xl:w-auto gap-2 overflow-x-auto no-scrollbar pb-2 xl:pb-0">
                {[
                  { id: 'text', icon: FileText, label: 'Text' },
                  { id: 'image', icon: ImageIcon, label: 'Image' },
                  { id: 'document', icon: FileIcon, label: 'Doc' },
                  { id: 'audio_file', icon: Music, label: 'Audio' },
                ].map((mode) => (
                  <button
                    key={mode.id}
                    onClick={() => { setInputMode(mode.id as InputMode); clearMedia(); setInputText(''); }}
                    className={`flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-bold border-2 transition-all whitespace-nowrap ${
                      inputMode === mode.id 
                        ? 'bg-text-primary text-bg-secondary border-text-primary shadow-[4px_4px_0px_0px_var(--btn-border-glow)] -translate-y-1' 
                        : 'bg-transparent border-transparent text-text-secondary hover:bg-bg-primary hover:border-border-primary'
                    }`}
                  >
                    <mode.icon size={18} />
                    {mode.label}
                  </button>
                ))}
             </div>

             {/* Live Button */}
             <button
                onClick={() => setIsLiveSessionOpen(true)}
                className="w-full xl:w-auto group flex items-center justify-center gap-3 px-8 py-3 bg-bg-secondary text-btn-border-glow border-3 border-btn-glow rounded-xl hover:shadow-glow transition-all hover:-translate-y-1 font-bold tracking-wide"
              >
                <div className="w-3 h-3 bg-btn-border-glow rounded-full animate-pulse" />
                LIVE SESSION
              </button>
          </div>

          {/* Main Card Area */}
          <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-12 min-h-[500px]">

            {/* Input Side - Accent Mint */}
            <div className="flex flex-col bg-accent-mint border-3 border-border-primary rounded-4xl p-6 md:p-8 relative transition-transform hover:-translate-y-1 hover:shadow-brutal-lg duration-300">
               <div className="flex items-center justify-between mb-6">
                  <div className="px-4 py-1 bg-text-primary text-bg-secondary text-xs font-bold uppercase rounded-full tracking-wider">
                    Input Source
                  </div>
                  {selectedMedia && (
                    <button onClick={clearMedia} className="p-2 rounded-full hover:bg-black/10 transition-colors">
                      <X size={20} className="text-text-primary" />
                    </button>
                  )}
               </div>

               <div className="flex-1 flex flex-col">
                  {inputMode === 'text' ? (
                     <textarea
                       value={inputText}
                       onChange={(e) => setInputText(e.target.value)}
                       placeholder="Type your text here..."
                       className="w-full h-full bg-transparent border-none outline-none resize-none text-2xl md:text-3xl text-text-primary placeholder-text-secondary/50 font-medium leading-relaxed"
                       spellCheck={false}
                     />
                  ) : (
                     <div className="flex-1 flex flex-col items-center justify-center border-3 border-dashed border-text-primary/20 rounded-3xl hover:bg-black/5 hover:border-text-primary/40 transition-all cursor-pointer relative overflow-hidden group"
                          onClick={() => !selectedMedia && fileInputRef.current?.click()}>

                        <input type="file" accept={getAcceptType()} className="hidden" ref={fileInputRef} onChange={handleFileUpload} />

                        {selectedMedia ? (
                          <div className="flex flex-col items-center z-10 p-8 w-full">
                            {inputMode === 'image' && <img src={selectedMedia.url} className="max-h-64 rounded-xl border-3 border-border-primary shadow-brutal mb-6 object-contain bg-bg-secondary" />}
                            <div className="flex items-center gap-3 bg-bg-secondary px-6 py-3 rounded-xl border-3 border-border-primary shadow-brutal">
                               <FileIcon size={24} className="text-text-primary" />
                               <span className="font-bold text-text-primary">{selectedMedia.name}</span>
                            </div>
                          </div>
                        ) : (
                          <div className="text-center p-8 transform group-hover:scale-105 transition-transform">
                             <div className="w-20 h-20 mx-auto mb-6 rounded-2xl bg-bg-secondary border-3 border-border-primary flex items-center justify-center shadow-brutal">
                                <Upload size={32} className="text-text-primary" />
                             </div>
                             <p className="text-xl font-bold text-text-primary">Upload {inputMode.replace('_', ' ')}</p>
                             <p className="text-text-secondary mt-2">Click to browse files</p>
                          </div>
                        )}
                     </div>
                  )}
               </div>
            </div>

            {/* Middle Action / Output Container */}
            <div className="flex flex-col gap-6">
                {/* Action Bar */}
                <div className="bg-bg-secondary border-3 border-border-primary rounded-3xl p-4 flex flex-col sm:flex-row items-center gap-4 shadow-brutal">
                   <div className="flex-1 w-full">
                     <LanguageSelector 
                       selectedLanguage={targetLanguage}
                       onSelectLanguage={setTargetLanguage}
                       label="Translate To"
                     />
                   </div>
                   <button
                     onClick={handleTranslate}
                     disabled={isTranslating || (inputMode === 'text' ? !inputText : !selectedMedia)}
                     className="w-full sm:w-auto h-14 px-8 bg-btn-bg text-btn-text border-3 border-btn-glow rounded-xl font-bold text-lg shadow-[4px_4px_0px_0px_var(--btn-border-glow)] hover:translate-y-[-2px] hover:shadow-[6px_6px_0px_0px_var(--btn-border-glow)] active:translate-y-[0px] active:shadow-[2px_2px_0px_0px_var(--btn-border-glow)] transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed disabled:shadow-none disabled:translate-y-0"
                   >
                     {isTranslating ? <Loader2 className="animate-spin" /> : <Wand2 size={24} />}
                     <span>Translate</span>
                   </button>
                </div>

                {/* Output Side - Accent Sky */}
                <div className="flex-1 flex flex-col bg-accent-sky border-3 border-border-primary rounded-4xl p-6 md:p-8 relative transition-transform hover:-translate-y-1 hover:shadow-brutal-lg duration-300">
                   <div className="flex items-center justify-between mb-6">
                      <div className="px-4 py-1 bg-text-primary text-bg-secondary text-xs font-bold uppercase rounded-full tracking-wider">
                        Result
                      </div>
                      <div className="flex gap-2">
                         {result && (
                            <span className="hidden sm:inline-block px-3 py-1 rounded-lg bg-bg-secondary border-2 border-border-primary text-xs font-bold text-text-secondary">
                               Detected: <span className="text-text-primary">{result.detectedSourceLanguage}</span>
                            </span>
                         )}
                         <button 
                           onClick={() => result && handleCopy(result.translatedText)} 
                           className="p-2 rounded-lg hover:bg-black/10 transition-colors text-text-primary disabled:opacity-30"
                           disabled={!result}
                         >
                           <Copy size={20} />
                         </button>
                      </div>
                   </div>

                   <div className="flex-1 overflow-y-auto custom-scrollbar">
                      {isTranslating ? (
                         <div className="h-full flex flex-col items-center justify-center gap-6 text-text-secondary">
                            <div className="w-20 h-20 rounded-full border-4 border-text-secondary/20 border-t-text-primary animate-spin" />
                            <p className="animate-pulse font-bold text-lg">Generating translation...</p>
                         </div>
                      ) : result ? (
                         <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
                            <p className="text-2xl md:text-3xl text-text-primary font-medium leading-relaxed whitespace-pre-wrap">
                               {result.translatedText}
                            </p>
                            {result.transcribedText && inputMode !== 'text' && (
                               <div className="mt-10 pt-8 border-t-3 border-text-primary/10">
                                  <p className="text-xs font-extrabold text-text-secondary uppercase mb-4 tracking-widest">Original Transcription</p>
                                  <p className="text-base text-text-secondary font-mono leading-relaxed bg-bg-secondary/50 p-6 rounded-2xl border-2 border-text-primary/10">
                                     {result.transcribedText}
                                  </p>
                               </div>
                            )}
                         </div>
                      ) : (
                         <div className="h-full flex flex-col items-center justify-center opacity-40">
                            <Bot size={80} className="mb-6 text-text-primary" />
                            <p className="text-text-primary font-bold text-xl">Ready to translate</p>
                         </div>
                      )}
                   </div>
                </div>
            </div>

          </div>

        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useMemo, useState } from 'react';
import { Trash2, Image as ImageIcon, Type, ArrowRight, Search, FileText, Music, History } from 'lucide-react';
import { TranslationHistoryItem, InputMode } from '../types';

interface HistorySidebarProps {
  history: TranslationHistoryItem[];
  onClearHistory: () => void;
  onSelectHistoryItem: (item: TranslationHistoryItem) => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onClearHistory, onSelectHistoryItem }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredHistory = useMemo(() => {
    if (!searchTerm.trim()) return history;

    const lowerTerm = searchTerm.toLowerCase();

    return history.filter(item => {
      const inSource = item.transcribedText?.toLowerCase().includes(lowerTerm);
      const inTranslation = item.translatedText.toLowerCase().includes(lowerTerm);
      const inLanguage = item.targetLanguage.toLowerCase().includes(lowerTerm);
      const inDetected = item.detectedSourceLanguage.toLowerCase().includes(lowerTerm);
      return inSource || inTranslation || inLanguage || inDetected;
    });
  }, [history, searchTerm]);

  const getIconForType = (type: string) => {
    switch (type as InputMode | 'live_session') {
      case 'image': return <ImageIcon size={14} />;
      case 'document': return <FileText size={14} />;
      case 'audio_file': return <Music size={14} />;
      default: return <Type size={14} />;
    }
  };

  return (
    <div className="h-full flex flex-col w-full bg-bg-secondary">
      {/* Header */}
      <div className="p-6 pb-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2 text-text-primary">
          <History size={18} className="text-text-secondary" />
          <h2 className="text-sm font-bold tracking-widest uppercase text-text-secondary">Recent Activity</h2>
        </div>
        {history.length > 0 && (
          <button 
            onClick={onClearHistory}
            className="p-2 rounded-lg text-text-secondary hover:text-btn-border-glow hover:bg-bg-primary transition-all border-2 border-transparent hover:border-btn-border-glow"
          >
            <Trash2 size={16} />
          </button>
        )}
      </div>

      {/* Search Bar */}
      <div className="px-6 pb-6 shrink-0">
         <div className="relative group">
            <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-text-secondary group-focus-within:text-text-primary transition-colors" />
            <input 
               type="text" 
               placeholder="Search..."
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="w-full bg-bg-primary text-text-primary text-sm font-medium rounded-xl pl-10 pr-4 py-3 border-2 border-transparent focus:border-border-primary focus:bg-bg-secondary outline-none transition-all placeholder-text-secondary/50"
            />
         </div>
      </div>

      {/* List */}
      <div className="flex-1 overflow-y-auto px-4 pb-4 space-y-3">
        {filteredHistory.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-48 text-text-secondary text-sm font-medium">
            {searchTerm ? <p>No matches found</p> : <p>History is empty</p>}
          </div>
        ) : (
          filteredHistory.map((item) => (
            <button
              key={item.id}
              onClick={() => onSelectHistoryItem(item)}
              className="w-full text-left bg-bg-primary hover:bg-accent-lavender border-2 border-transparent hover:border-border-primary rounded-xl p-4 transition-all group relative overflow-hidden"
            >
              <div className="flex items-center justify-between mb-3">
                <span className="text-[10px] font-bold text-text-secondary bg-bg-secondary border border-border-primary/20 px-2 py-1 rounded-md flex items-center gap-1.5 uppercase tracking-wider">
                  {getIconForType(item.type)}
                  <span>{item.detectedSourceLanguage}</span>
                  <ArrowRight size={10} />
                  <span>{item.targetLanguage}</span>
                </span>
                <span className="text-[10px] text-text-secondary font-mono font-bold">
                  {new Date(item.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
              <p className="text-sm text-text-primary font-bold line-clamp-2 mb-2 leading-tight">
                {item.transcribedText || "Media Content"}
              </p>
              <p className="text-xs text-text-secondary line-clamp-1 italic font-medium">
                {item.translatedText}
              </p>
            </button>
          ))
        )}
      </div>
    </div>
  );
};

