    <div className="relative w-full" ref={containerRef}>
      {label && <label className="block text-xs font-extrabold text-text-secondary uppercase tracking-widest mb-2 px-1">{label}</label>}

      <button
        onClick={() => setIsOpen(!isOpen)}
