import { GoogleGenAI, Type } from "@google/genai";
import { TranslationResult } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API_KEY is missing from environment variables.");
}

// Export the instance for use in LiveSession
export const ai = new GoogleGenAI({ apiKey: apiKey || 'dummy-key-for-build' });

/**
 * Streams the translation of text content for instant feedback.
 */
export async function* translateTextStream(
  text: string, 
  targetLanguage: string
): AsyncGenerator<string, void, unknown> {
  try {
    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: `Translate the following text into ${targetLanguage}. Do not provide any preamble or explanation, just the translation:\n\n"${text}"`,
    });

    for await (const chunk of responseStream) {
      if (chunk.text) {
        yield chunk.text;
      }
    }
  } catch (error) {
    console.error("Stream Error:", error);
    throw error;
  }
}

/**
 * Translates media content (Image, Audio, Doc) to the target language with structured JSON output.
 */
export const translateContent = async (
  input: string | { data: string; mimeType: string },
  targetLanguage: string
): Promise<TranslationResult> => {
  try {
    const isMedia = typeof input !== 'string';

    // Fallback for text if called via this method (legacy support), though stream is preferred
    if (!isMedia) {
       // Simple wrapper to match expected type if not streaming
       const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Translate the following text into ${targetLanguage}: "${input}"`,
       });
       return {
         detectedSourceLanguage: "Detected",
         transcribedText: input as string,
         translatedText: response.text || ""
       };
    }

    const parts = [];
    const mediaInput = input as { data: string; mimeType: string };

    parts.push({
      inlineData: {
        data: mediaInput.data,
        mimeType: mediaInput.mimeType,
      }
    });

    // Customize prompt based on mime type
    let promptText = "";
    if (mediaInput.mimeType.startsWith("image/")) {
      promptText = `Analyze this image. Transcribe any text found in the image exactly as it appears. Then, translate that text into ${targetLanguage}.`;
    } else if (mediaInput.mimeType === "application/pdf" || mediaInput.mimeType === "text/plain") {
       promptText = `Read this document. Extract the text content and translate it into ${targetLanguage}.`;
    } else if (mediaInput.mimeType.startsWith("audio/")) {
       promptText = `Listen to this audio file. Transcribe the spoken content exactly. Then, translate the transcription into ${targetLanguage}.`;
    } else {
       promptText = `Analyze this content and translate it into ${targetLanguage}.`;
    }

    parts.push({ text: promptText });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: parts
      },
      config: {
        systemInstruction: "You are an expert translator. Automatically detect the source language. Return the result in strictly valid JSON format.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            detectedSourceLanguage: { type: Type.STRING, description: "The name of the language detected in the input." },
            transcribedText: { type: Type.STRING, description: "The original text found in the input (OCR/Transcription)." },
            translatedText: { type: Type.STRING, description: "The final translation." }
          },
          required: ["detectedSourceLanguage", "transcribedText", "translatedText"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    return JSON.parse(text) as TranslationResult;

  } catch (error) {
    console.error("Translation Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  ArrowRightLeft, 
  Bot, 
  Image as ImageIcon, 
  X, 
  Upload, 
  Copy, 
  Loader2, 
  Sparkles,
  Menu,
  FileText,
  Music,
  FileIcon,
  Wand2,
  Moon,
  Sun
} from 'lucide-react';
import LanguageSelector from './components/LanguageSelector';
import HistorySidebar from './components/HistorySidebar';
import LiveSession from './components/LiveSession';
import { SUPPORTED_LANGUAGES, DEFAULT_TARGET_LANGUAGE } from './constants';
import { Language, TranslationResult, TranslationHistoryItem, InputMode } from './types';
import { translateContent, translateTextStream } from './services/geminiService';

const App: React.FC = () => {
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme');
    if (saved) return saved as 'light' | 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const [inputMode, setInputMode] = useState<InputMode>('text');
  const [inputText, setInputText] = useState('');
  const [selectedMedia, setSelectedMedia] = useState<{ url: string; base64: string; mimeType: string; name: string } | null>(null);
  const [targetLanguage, setTargetLanguage] = useState<Language>(DEFAULT_TARGET_LANGUAGE);
  const [isTranslating, setIsTranslating] = useState(false);
  const [result, setResult] = useState<TranslationResult | null>(null);

  const [history, setHistory] = useState<TranslationHistoryItem[]>(() => {
    try {
      const saved = localStorage.getItem('polyglot_history');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  useEffect(() => {
    localStorage.setItem('polyglot_history', JSON.stringify(history));
  }, [history]);

  const [showMobileHistory, setShowMobileHistory] = useState(false);
  const [isLiveSessionOpen, setIsLiveSessionOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = reader.result as string;
        const base64Data = base64String.split(',')[1];
        setSelectedMedia({
          url: URL.createObjectURL(file),
          base64: base64Data,
          mimeType: file.type,
          name: file.name
        });
        setResult(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const clearMedia = () => {
    setSelectedMedia(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
    setResult(null);
  };

  const handleTranslate = async () => {
    if (inputMode === 'text' && !inputText.trim()) return;
    if (inputMode !== 'text' && !selectedMedia) return;

    setIsTranslating(true);
    setResult(null);

    try {
      // Stream path for Text
      if (inputMode === 'text') {
        let streamedText = "";
        // Initialize result immediately
        setResult({
          detectedSourceLanguage: "Auto",
          transcribedText: inputText,
          translatedText: ""
        });

        const stream = translateTextStream(inputText, targetLanguage.name);

        for await (const chunk of stream) {
          streamedText += chunk;
          setResult(prev => ({
            ...prev!,
            translatedText: streamedText
          }));
        }

        // Save to history after stream completes
        const newHistoryItem: TranslationHistoryItem = {
          id: Date.now().toString(),
          timestamp: Date.now(),
          detectedSourceLanguage: "Auto",
          transcribedText: inputText,
          translatedText: streamedText,
          targetLanguage: targetLanguage.name,
          type: 'text',
          preview: inputText
        };
        setHistory(prev => [newHistoryItem, ...prev]);

      } else {
        // Standard path for Media (needs JSON analysis)
        const input = { data: selectedMedia!.base64, mimeType: selectedMedia!.mimeType };
        const translation = await translateContent(input, targetLanguage.name);

        setResult(translation);

        const newHistoryItem: TranslationHistoryItem = {
          id: Date.now().toString(),
          timestamp: Date.now(),
          detectedSourceLanguage: translation.detectedSourceLanguage,
          transcribedText: translation.transcribedText,
          translatedText: translation.translatedText,
          targetLanguage: targetLanguage.name,
          type: inputMode,
          preview: selectedMedia?.name || 'Media File'
        };
        setHistory(prev => [newHistoryItem, ...prev]);
      }

    } catch (error) {
      console.error(error);
      alert("Translation failed.");
    } finally {
      setIsTranslating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
  };

